  background-color: ${({ variant, theme }) => getBackground(variant, theme)};
  justify-content: center;
  align-items: center;
  ${({ theme, variant }) => variant === 'surface' && `
    border-width: 1px;
    border-color: ${theme.colors.outline_variant};
  `}
`;

