import React, { useRef, useEffect } from 'react';
import { Animated, View } from 'react-native';
import Ionicons from 'react-native-vector-icons/Ionicons';
import { useTheme } from 'styled-components/native';
import { useLocale } from '@/constants/localization';
import { OlaMap, Camera, UserLocation } from '@/components/organisms/OlaMap';
import {
  PinContainer,
  PinWrapper,
  TooltipBubble,
  TooltipText,
  PinShadow,
  SelectButtonContainer,
  GradientOverlay,
  LocationPreviewContainer,
  LocationPreviewTitle,
  LocationPreviewText
} from './MapPickerTemplate.styles';
import { MapSearchOverlayProps, MapSearchOverlay } from '@/components/organisms/MapSearchOverlay';
import { LocationDetailsCardProps } from '@/components/molecules/LocationDetailsCard';
import { ScreenShell } from '@/components/molecules/ScreenShell';
import { MapControlsFABs } from '@/components/molecules/MapControlsFABs';
import { moderateScale, scale, verticalScale } from '@/styles';

import { UserLocationMarker } from '@/components/atoms/UserLocationMarker';
import { Button } from '@/components/atoms/Button';
import { useSafeAreaInsets } from 'react-native-safe-area-context';

interface ExtendedUserLocationProps extends React.ComponentProps<typeof UserLocation> {
  onUpdate?: (location: any) => void;
  showsUserHeadingIndicator?: boolean;
}

const MapLibreUserLocation = UserLocation as React.ComponentType<ExtendedUserLocationProps>;

export interface MapPickerTemplateProps {
  pickerType: 'start' | 'destination' | 'middleStop';
  region: {
    latitude: number;
    longitude: number;
  };
  onRegionChangeComplete: (feature: any) => void;
  onRegionWillChange?: () => void;
  isMoving?: boolean;
  onUserLocationUpdate?: (location: any) => void;
  onLocateMe?: () => void;
  heading?: number;
  hasPermission?: boolean;
  searchOverlayProps: Omit<MapSearchOverlayProps, 'isCondensed'>;
  locationDetailsProps: LocationDetailsCardProps;
  mapRef?: React.RefObject<any>;
  cameraRef?: React.RefObject<any>;
  isInitiallyCentered: boolean;
  setIsInitiallyCentered: (val: boolean) => void;
  isMapVisible: boolean;
  onZoomIn?: () => void;
  onZoomOut?: () => void;
  zoom?: number;
  setIsMapVisible: (val: boolean) => void;
  isMapMounted: boolean;
}

export const MapPickerTemplate: React.FC<MapPickerTemplateProps> = ({
  pickerType,
  region,
  mapRef,
  cameraRef,
  onRegionChangeComplete,
  onRegionWillChange,
  isMoving,
  onUserLocationUpdate,
  onLocateMe,
  heading,
  hasPermission,
  searchOverlayProps,
  locationDetailsProps,
  isInitiallyCentered,
  setIsInitiallyCentered,
  isMapVisible,
  onZoomIn,
  onZoomOut,
  zoom,
  setIsMapVisible,
  isMapMounted,
}) => {
  const theme = useTheme();
  const { mapPicker } = useLocale();
  const insets = useSafeAreaInsets();
  const pinAnim = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    if (!isInitiallyCentered) {
      setIsInitiallyCentered(true);
    }
  }, [isInitiallyCentered, setIsInitiallyCentered]);

  useEffect(() => {
    Animated.spring(pinAnim, {
      toValue: isMoving ? 1 : 0,
      useNativeDriver: true,
      friction: 8,
      tension: 40,
    }).start();
  }, [isMoving, pinAnim]);

  const pinTranslateY = pinAnim.interpolate({
    inputRange: [0, 1],
    outputRange: [0, -verticalScale(20)],
  });

  const pinScale = pinAnim.interpolate({
    inputRange: [0, 1],
    outputRange: [1, 1.1],
  });

  const shadowOpacity = pinAnim.interpolate({
    inputRange: [0, 1],
    outputRange: [1, 0.3],
  });

  const shadowScale = pinAnim.interpolate({
    inputRange: [0, 1],
    outputRange: [1, 0.6],
  });

  return (
    <ScreenShell title={mapPicker.title} onBack={searchOverlayProps.onBackPress}>
      <MapSearchOverlay
        {...searchOverlayProps}
        isCondensed={isMapVisible}
      />

      {/* Map Layer - Warm Mounted */}
      {isMapMounted && (
        <OlaMap
          ref={mapRef}
          onRegionWillChange={onRegionWillChange}
          onRegionDidChange={onRegionChangeComplete}
          style={{
            flex: 1,
            width: '100%',
            height: '100%',
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            zIndex: 0,
            opacity: isMapVisible ? 1 : 0
          }}
          pointerEvents={isMapVisible ? 'auto' : 'none'}
        >
          <Camera
            ref={cameraRef}
            center={[region.longitude, region.latitude]}
            zoom={zoom ?? 14}
          />
          {hasPermission && (
            <MapLibreUserLocation
              onUpdate={onUserLocationUpdate}
              showsUserHeadingIndicator={true}
            >
              <UserLocationMarker heading={heading} />
            </MapLibreUserLocation>
          )}
        </OlaMap>
      )}

      {isMapVisible && (
        <>
          <GradientOverlay colors={['transparent', 'rgba(0,0,0,0.05)']} />

          <PinContainer pointerEvents="none">
            <PinWrapper
              as={Animated.View}
              style={{
                transform: [
                  { translateY: pinTranslateY },
                  { scale: pinScale }
                ]
              }}
            >
              <TooltipBubble
                as={Animated.View}
                style={{
                  opacity: pinAnim.interpolate({
                    inputRange: [0, 0.2, 1],
                    outputRange: [1, 0, 0]
                  })
                }}
              >
                <TooltipText>
                  {pickerType === 'start'
                    ? mapPicker.setPickup
                    : pickerType === 'destination'
                      ? mapPicker.setDestination
                      : mapPicker.setStop}
                </TooltipText>
              </TooltipBubble>

              <Ionicons
                name="pin-sharp"
                size={moderateScale(28)}
                color={theme.colors.primary_container}
              />
              <PinShadow
                as={Animated.View}
                style={{
                  opacity: shadowOpacity,
                  transform: [{ scale: shadowScale }]
                }}
              />
            </PinWrapper>
          </PinContainer>

          <SelectButtonContainer style={{ paddingBottom: Math.max(insets.bottom, verticalScale(12)) }}>
            <LocationPreviewContainer>
              <Ionicons
                name="locate-sharp"
                size={moderateScale(18)}
                color={theme.colors.primary}
                style={{ marginRight: scale(8) }}
              />
              <View style={{ flex: 1, justifyContent: 'center' }}>
                <LocationPreviewTitle numberOfLines={1}>
                  {locationDetailsProps.locationName || 'Select a spot on the map'}
                </LocationPreviewTitle>
                {!!locationDetailsProps.locationAddress && (
                  <LocationPreviewText numberOfLines={1}>
                    {locationDetailsProps.locationAddress}
                  </LocationPreviewText>
                )}
              </View>
            </LocationPreviewContainer>

            <Button
              onPress={locationDetailsProps.onSelect}
              disabled={locationDetailsProps.disabled || !locationDetailsProps.locationName}
            >
              {mapPicker.selectLocation}
            </Button>
          </SelectButtonContainer>

          <MapControlsFABs
            onZoomIn={onZoomIn}
            onZoomOut={onZoomOut}
            onLocateMe={onLocateMe}
          />
        </>
      )}
    </ScreenShell>
  );
};

import React, { useMemo, useEffect, useRef } from 'react';
import { Animated } from 'react-native';
import MaterialIcons from 'react-native-vector-icons/MaterialIcons';
import { useTheme } from 'styled-components/native';
import { useLocale } from '@/constants/localization';
import { moderateScale, verticalScale } from '@/styles';
import { Location } from '@/store/useLocationStore';
import { OlaMap, Camera, GeoJSONSource, Layer, Marker } from '@/components/organisms/OlaMap';
import {
  MiddleStopSearchOverlay,
  LocationOption,
} from '@/components/organisms/MiddleStopSearchOverlay';
import { ScreenShell } from '@/components/molecules/ScreenShell';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import { Button } from '@/components/atoms/Button';
import { MapControlsFABs } from '@/components/molecules/MapControlsFABs';
import { SnapResult } from '@/utils/routeSnap';
import * as S from './MiddleStopMapTemplate.styles';

export interface MiddleStopMapTemplateProps {
  // State
  isSearching: boolean;
  isLoading: boolean;
  isReverseGeocoding?: boolean;
  isMoving: boolean;
  searchQuery: string;
  searchResults: LocationOption[];
  selectedLocation: LocationOption | null;
  snapResult: SnapResult | null;
  canConfirm: boolean;

  // Display
  routeTitle: string;
  distanceText: string;
  stopsCount: number;
  history: Location[];
  initialCenter: [number, number];

  // GeoJSON
  routeGeoJSON: GeoJSON.FeatureCollection | null;
  connectorGeoJSON: GeoJSON.FeatureCollection | null;
  routeBounds: [number, number, number, number];
  routeCoordinates: [number, number][];

  // Refs
  mapRef: React.RefObject<any>;
  cameraRef: React.RefObject<any>;

  // Markers
  startLocation: Location | null;
  destinationLocation: Location | null;

  // Handlers
  onBackPress: () => void;
  onSearchPress: () => void;
  onChangeSearch: (query: string) => void;
  onSelectLocation: (loc: LocationOption) => void;
  onSelectHistory: (loc: Location) => void;
  onConfirm: () => void;
  onZoomIn?: () => void;
  onZoomOut?: () => void;
  onRegionWillChange?: () => void;
  onRegionIsChanging?: (event: any) => void;
  onRegionChangeComplete?: (viewState: any) => void;
  onMapPress?: (feature: any) => void;
  isMapMounted: boolean;
}

const ROUTE_LINE_STYLE = {
  lineColor: '#4A90D9',
  lineWidth: 4,
  lineOpacity: 0.85,
  lineCap: 'round' as const,
  lineJoin: 'round' as const,
};

const CONNECTOR_LINE_STYLE = {
  lineColor: '#FF8C42',
  lineWidth: 2.5,
  lineOpacity: 0.8,
  lineDasharray: [8, 6],
  lineCap: 'round' as const,
};

export const MiddleStopMapTemplate: React.FC<MiddleStopMapTemplateProps> = React.memo(({
  isSearching,
  isLoading,
  isReverseGeocoding,
  isMoving,
  searchQuery,
  searchResults,
  selectedLocation,
  snapResult,
  canConfirm,
  routeTitle,
  distanceText,
  stopsCount,
  history,
  initialCenter,
  routeGeoJSON,
  connectorGeoJSON,
  routeBounds,
  routeCoordinates,
  mapRef,
  cameraRef,
  startLocation,
  destinationLocation,
  onBackPress,
  onSearchPress,
  onChangeSearch,
  onSelectLocation,
  onSelectHistory,
  onConfirm,
  onZoomIn,
  onZoomOut,
  onRegionWillChange,
  onRegionIsChanging,
  onRegionChangeComplete,
  onMapPress,
  isMapMounted,
}) => {
  const theme = useTheme();
  const { middleStopMap: t } = useLocale();
  const insets = useSafeAreaInsets();

  const isWarning = snapResult ? !snapResult.isWithinThreshold : false;

  const pinAnim = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    Animated.spring(pinAnim, {
      toValue: isMoving ? 1 : 0,
      useNativeDriver: true,
      friction: 8,
      tension: 40,
    }).start();
  }, [isMoving, pinAnim]);

  const pinTranslateY = pinAnim.interpolate({
    inputRange: [0, 1],
    outputRange: [0, -verticalScale(20)],
  });

  const pinScale = pinAnim.interpolate({
    inputRange: [0, 1],
    outputRange: [1, 1.1],
  });

  const shadowOpacity = pinAnim.interpolate({
    inputRange: [0, 1],
    outputRange: [1, 0.3],
  });

  const shadowScale = pinAnim.interpolate({
    inputRange: [0, 1],
    outputRange: [1, 0.6],
  });

  return (
    <ScreenShell
      title={t.headerTitle}
      onBack={onBackPress}
    >
      <S.ContentArea>
        {/* Map Layer - Always mounted to prevent camera race conditions */}
        <S.MapLayer pointerEvents={isSearching ? 'none' : 'auto'}>
          {isMapMounted && (
            <OlaMap
              ref={mapRef}
              onPress={onMapPress}
              onRegionWillChange={onRegionWillChange}
              onRegionIsChanging={onRegionIsChanging}
              onRegionDidChange={onRegionChangeComplete}
              style={{ flex: 1, width: '100%', height: '100%' }}
            >
              <Camera
                ref={cameraRef}
                center={initialCenter}
                zoom={14}
              />

              {/* Main route polyline */}
              {routeGeoJSON && (
                <>
                  <GeoJSONSource
                    id="route-line-source"
                    data={routeGeoJSON}
                  />
                  <Layer
                    id="route-line-layer"
                    source="route-line-source"
                    type="line"
                    style={ROUTE_LINE_STYLE}
                  />
                </>
              )}

              {/* Dashed connector line */}
              {connectorGeoJSON && (
                <>
                  <GeoJSONSource
                    id="connector-line-source"
                    data={connectorGeoJSON}
                  />
                  <Layer
                    id="connector-line-layer"
                    source="connector-line-source"
                    type="line"
                    style={CONNECTOR_LINE_STYLE}
                  />
                </>
              )}

              {/* Start marker */}
              {startLocation && (
                <Marker
                  lngLat={[startLocation.longitude, startLocation.latitude]}
                >
                  <S.MarkerDotOuter color={theme.colors.primary}>
                    <S.MarkerDot color={theme.colors.primary} size={10} />
                  </S.MarkerDotOuter>
                </Marker>
              )}

              {/* Destination marker */}
              {destinationLocation && (
                <Marker
                  lngLat={[destinationLocation.longitude, destinationLocation.latitude]}
                >
                  <S.MarkerDotOuter color={theme.colors.error}>
                    <S.MarkerDot color={theme.colors.error} size={10} />
                  </S.MarkerDotOuter>
                </Marker>
              )}

              {/* Snapped point on route */}
              {snapResult && (
                <Marker
                  lngLat={snapResult.snappedPoint}
                >
                  <S.MarkerDot
                    color={isWarning ? theme.colors.error : theme.colors.primary}
                    size={8}
                  />
                </Marker>
              )}
            </OlaMap>
          )}
        </S.MapLayer>

        {/* Search mode overlay */}
        {isSearching && (
          <S.SearchOverlayLayer>
            <MiddleStopSearchOverlay
              searchQuery={searchQuery}
              onChangeSearch={onChangeSearch}
              suggestedLocations={searchResults}
              recentHistory={history}
              onSelectLocation={onSelectLocation}
              onSelectHistory={onSelectHistory}
              isLoading={isLoading}
            />
          </S.SearchOverlayLayer>
        )}

        {!isSearching && (
          <>
            {/* Centered Map Pin Selection Overlay */}
            <S.PinContainer pointerEvents="none">
              <S.PinWrapper
                as={Animated.View}
                style={{
                  transform: [
                    { translateY: pinTranslateY },
                    { scale: pinScale }
                  ]
                }}
              >
                <S.TooltipBubble 
                  as={Animated.View} 
                  style={{ 
                    opacity: pinAnim.interpolate({
                      inputRange: [0, 0.2, 1],
                      outputRange: [1, 0, 0]
                    }) 
                  }}
                >
                  <S.TooltipText>
                    {t.confirmStop}
                  </S.TooltipText>
                </S.TooltipBubble>

                <MaterialIcons
                  name="place" 
                  size={moderateScale(32)} 
                  color={theme.colors.primary} 
                />
                <S.PinShadow 
                  as={Animated.View} 
                  style={{ 
                    opacity: shadowOpacity,
                    transform: [{ scale: shadowScale }]
                  }} 
                />
              </S.PinWrapper>
            </S.PinContainer>

            {/* Gradient overlay */}
            <S.MapGradientOverlay />

            {/* Floating search bar on map */}
            <S.FloatingSearchBar onPress={onSearchPress} activeOpacity={0.8}>
              <MaterialIcons
                name="search"
                size={moderateScale(22)}
                color={theme.colors.primary}
              />
              <S.FloatingSearchText>{t.searchPlaceholder}</S.FloatingSearchText>
            </S.FloatingSearchBar>

            {/* Permanent Warning Banner if too far from route */}
            {isWarning && (
              <S.WarningBanner>
                <MaterialIcons
                  name="warning"
                  size={moderateScale(20)}
                  color={theme.colors.error}
                />
                <S.WarningContent>
                  <S.WarningTitle>{t.tooFarFromRoute}</S.WarningTitle>
                  <S.WarningDescription>{t.tooFarFromRouteMsg}</S.WarningDescription>
                </S.WarningContent>
              </S.WarningBanner>
            )}

            {/* Map controls */}
            <MapControlsFABs
              onZoomIn={onZoomIn}
              onZoomOut={onZoomOut}
            />

            {/* Bottom card with stop info + confirm */}
            {selectedLocation && (
              <S.BottomCard style={{ paddingBottom: Math.max(insets.bottom + 16, 32) }}>
                <S.BottomGradient />

                <S.StopInfoCard>
                  <S.StopInfoRow>
                    <S.StopInfoLeft>
                      <S.StopNameText numberOfLines={1}>
                        {isReverseGeocoding ? 'Locating...' : selectedLocation.name}
                      </S.StopNameText>
                      {!!(isReverseGeocoding || selectedLocation.address) && (
                        <S.StopAddressText numberOfLines={1}>
                          {isReverseGeocoding ? 'Please wait...' : selectedLocation.address}
                        </S.StopAddressText>
                      )}
                    </S.StopInfoLeft>

                    {!isReverseGeocoding && snapResult && (
                      <S.DistancePill isWarning={isWarning}>
                        <MaterialIcons
                          name={isWarning ? 'warning' : 'near-me'}
                          size={moderateScale(12)}
                          color={isWarning ? theme.colors.error : theme.colors.primary}
                        />
                        <S.DistancePillText isWarning={isWarning}>
                          {distanceText}
                        </S.DistancePillText>
                      </S.DistancePill>
                    )}
                  </S.StopInfoRow>
                </S.StopInfoCard>

                <Button
                  onPress={onConfirm}
                  disabled={!canConfirm || isReverseGeocoding}
                  icon="add-location-alt"
                  iconPosition="left"
                >
                  {t.confirmStop}
                </Button>
              </S.BottomCard>
            )}
          </>
        )}
      </S.ContentArea>
    </ScreenShell>
  );
});

