import { useState, useCallback, useEffect } from 'react';
import { Keyboard, Alert } from 'react-native';
import { useTranslation } from '@/hooks/useTranslation';
import { showNotification } from '@/components/organisms/GlobalNotification/GlobalNotification';
import { NotificationType } from '@/constants/enums';
import { getErrorMessage } from '@/utils/error';
import { useTruecaller, type TruecallerAndroidResponse } from '@ajitpatel28/react-native-truecaller';
import { useAuthStore } from '@/store/useAuthStore';
import { Logger } from '@/utils/logger';
import { useNetworkLoggerStore } from '@/store/useNetworkLoggerStore';
import {
  USER_DISMISS_CODES,
  TRANSIENT_SDK_CODES,
  executeTruecallerAuth,
  syncUserProfileAndData,
  getTruecallerOptions,
} from './truecallerHelper';

interface UseTruecallerLoginProps {
  setLoading: (loading: boolean) => void;
}

export const useTruecallerLogin = ({ setLoading }: UseTruecallerLoginProps) => {
  const { t } = useTranslation();
  const { setAuth } = useAuthStore();
  const [isTruecallerSupported, setIsTruecallerSupported] = useState(false);
  const [hasDismissedTruecaller, setHasDismissedTruecaller] = useState(false);

  const verifyTruecaller = useCallback(
    async (params: {
      authorizationCode?: string;
      codeVerifier?: string;
    }) => {
      setLoading(true);
      try {
        if (!params.authorizationCode) {
          showNotification(
            NotificationType.ERROR,
            t('notification.defaultErrorTitle'),
            t('login.truecallerInvalidCredentials')
          );
          setLoading(false);
          return;
        }

        const response = await executeTruecallerAuth(
          params.authorizationCode,
          params.codeVerifier
        );

        if (response.data.status === 'success' || response.status === 200) {
          const { token, userId, userProfileCompleted: completed } = response.data;
          await syncUserProfileAndData(userId, token, completed, setAuth);
          showNotification(
            NotificationType.SUCCESS,
            t('notification.welcomeSuccessTitle'),
            t('notification.welcomeBack')
          );
        } else {
          showNotification(
            NotificationType.ERROR,
            t('notification.defaultErrorTitle'),
            response.data.message || t('notification.defaultErrorMessage')
          );
        }
      } catch (error: any) {
        Logger.error('Truecaller login failed', error);
        showNotification(
          NotificationType.ERROR,
          t('notification.defaultErrorTitle'),
          getErrorMessage(error, t('login.truecallerLoginFailed'))
        );
      } finally {
        setLoading(false);
      }
    },
    [setAuth, t, setLoading]
  );

  const handleTruecallerSuccess = useCallback(
    (data: {
      accessToken?: string;
      authorizationCode?: string;
      codeVerifier?: string;
    }) => verifyTruecaller(data),
    [verifyTruecaller]
  );

  const androidSuccessHandler = useCallback((data: TruecallerAndroidResponse) => {
    useNetworkLoggerStore.getState().addLog({
      id: `tc-${Date.now()}`,
      method: 'SDK',
      url: 'truecaller://verify',
      requestHeaders: {},
      requestBody: null,
      responseStatus: 200,
      responseHeaders: null,
      responseBody: data,
      startTime: Date.now(),
      endTime: Date.now(),
      duration: 0,
      isError: false,
    });

    const accessToken = (data as any).accessToken || '';
    handleTruecallerSuccess({
      accessToken,
      authorizationCode: data.authorizationCode,
      codeVerifier: (data as any).codeVerifier,
    });
  }, [handleTruecallerSuccess]);

  const {
    initializeTruecallerSDK,
    openTruecallerForVerification,
    isSdkUsable,
    userProfile,
    error: truecallerError,
  } = useTruecaller(getTruecallerOptions(androidSuccessHandler));

  // Robust initialization logic with delay and retries
  useEffect(() => {
    let active = true;
    let timerId: ReturnType<typeof setTimeout>;
    let retries = 0;
    const maxRetries = 3;

    const init = () => {
      Logger.log(`Initializing Truecaller SDK (attempt ${retries + 1})...`);
      initializeTruecallerSDK()
        .then(() => isSdkUsable())
        .then((supported) => {
          Logger.log('Truecaller SDK support check:', supported);
          if (active) {
            setIsTruecallerSupported(supported);
          }
        })
        .catch((err) => {
          Logger.log(`Truecaller SDK init attempt ${retries + 1} failed:`, err);
          if (active) {
            if (retries < maxRetries) {
              retries++;
              timerId = setTimeout(init, 1000);
            } else {
              setIsTruecallerSupported(false);
            }
          }
        });
    };

    // Delay initialization to let Android Activity mount
    timerId = setTimeout(init, 500);

    return () => {
      active = false;
      clearTimeout(timerId);
    };
  }, [initializeTruecallerSDK, isSdkUsable]);

  useEffect(() => {
    if (userProfile) {
      handleTruecallerSuccess({ accessToken: (userProfile as any).accessToken || '' });
    }
  }, [userProfile, handleTruecallerSuccess]);

  useEffect(() => {
    Logger.log('Truecaller error event:', truecallerError);
    if (!truecallerError) return;

    const errorStr = String(truecallerError);

    useNetworkLoggerStore.getState().addLog({
      id: `tc-err-${Date.now()}`,
      method: 'SDK',
      url: 'truecaller://error',
      requestHeaders: {},
      requestBody: null,
      responseStatus: 400,
      responseHeaders: null,
      responseBody: { error: truecallerError },
      startTime: Date.now(),
      endTime: Date.now(),
      duration: 0,
      isError: true,
    });

    if (USER_DISMISS_CODES.test(errorStr)) {
      setHasDismissedTruecaller(true);
    } else if (TRANSIENT_SDK_CODES.test(errorStr)) {
      Logger.log('Truecaller transient SDK error ignored:', errorStr);
    } else {
      showNotification(
        NotificationType.ERROR,
        t('login.truecallerErrorTitle'),
        getErrorMessage(truecallerError, t('login.truecallerLoginFailed'))
      );
    }
  }, [truecallerError, t]);

  const handleTruecallerLogin = async () => {
    Keyboard.dismiss();
    try {
      if (await isSdkUsable()) {
        setHasDismissedTruecaller(false);
        await openTruecallerForVerification();
      } else {
        showNotification(
          NotificationType.ERROR,
          t('login.truecallerUnavailableTitle'),
          t('login.truecallerUnavailableMessage')
        );
      }
    } catch (err) {
      Logger.error('Could not start Truecaller login', err);
      showNotification(
        NotificationType.ERROR,
        t('notification.defaultErrorTitle'),
        t('login.truecallerStartError')
      );
    }
  };

  const handleInputFocus = async () => {
    if (isTruecallerSupported && !hasDismissedTruecaller) {
      Keyboard.dismiss();
      await handleTruecallerLogin();
    }
  };

  return {
    isTruecallerSupported,
    hasDismissedTruecaller,
    handleTruecallerLogin,
    handleInputFocus,
  };
};

import { useState, useCallback, useEffect } from 'react';
import { BackHandler, ToastAndroid } from 'react-native';
import { format, isBefore, startOfDay } from 'date-fns';
import { useRoute, useFocusEffect } from '@react-navigation/native';
import { useLocale } from '@/constants/localization';
import { useBookRideStore, RecentSearch } from '@/store/useBookRideStore';
import { useAppNavigation } from '@/hooks/useAppNavigation';
import rideService, { SearchRidePayload } from '@/serviceManager/rideService';
import { useTranslation } from '@/hooks/useTranslation';
import { showNotification } from '@/components/organisms/GlobalNotification/GlobalNotification';
import { NotificationType } from '@/constants/enums';
import { getErrorMessage } from '@/utils/error';

export const useBookRideInfo = () => {
  const { navigation, navigate } = useAppNavigation();
  const { bookRideInfo: t } = useLocale();
  const { t: translate } = useTranslation();
  const [isSearching, setIsSearching] = useState(false);
  const [isSwapped, setIsSwapped] = useState(false);

  useFocusEffect(
    useCallback(() => {
      setIsSearching(false);
      let backPressCount = 0;
      const onBackPress = () => {
        if (backPressCount === 0) {
          backPressCount++;
          ToastAndroid.show('Press back again to exit the app', ToastAndroid.SHORT);
          setTimeout(() => {
            backPressCount = 0;
          }, 2000);
          return true;
        } else {
          BackHandler.exitApp();
          return true;
        }
      };

      const subscription = BackHandler.addEventListener('hardwareBackPress', onBackPress);

      return () => {
        subscription.remove();
      };
    }, [])
  );

  const {
    startLocation,
    destinationLocation,
    travelDate,
    seatCount,
    recentSearches,
    rideType,
  } = useBookRideStore();

  const handlePressPickup = useCallback(() => {
    navigate('MapPicker', {
      type: 'start',
      module: 'search',
      returnTo: 'BookRideInfo',
    });
  }, [navigate]);

  const handlePressDestination = useCallback(() => {
    navigate('MapPicker', {
      type: 'destination',
      module: 'search',
      returnTo: 'BookRideInfo',
    });
  }, [navigate]);

  const handleSwapLocations = useCallback(() => {
    setIsSwapped(prev => !prev);
    const store = useBookRideStore.getState();
    const currentStart = store.startLocation;
    const currentDest = store.destinationLocation;

    store.setStartLocation(currentDest);
    store.setDestinationLocation(currentStart);
  }, []);

  const handleOpenDatePicker = useCallback(() => {
    navigate('BookDateSelection');
  }, [navigate]);

  const incrementPeople = useCallback(() => {
    const store = useBookRideStore.getState();
    store.setSeatCount(Math.min(store.seatCount + 1, 6));
  }, []);

  const decrementPeople = useCallback(() => {
    const store = useBookRideStore.getState();
    store.setSeatCount(Math.max(store.seatCount - 1, 1));
  }, []);

  const handleSearchRides = useCallback(async () => {
    const store = useBookRideStore.getState();
    const { startLocation: curStart, destinationLocation: curDest, travelDate: curDate, seatCount: curSeats, addRecentSearch, setSearchResults, rideType: curType } = store;

    if (curStart && curDest) {
      const selectedDate = curDate ? new Date(curDate) : new Date();
      if (isBefore(selectedDate, startOfDay(new Date()))) {
        store.setTravelDate(null);
        navigate('BookDateSelection');
        return;
      }

      try {
        setIsSearching(true);
        const payload: SearchRidePayload = {
          sourceLat: curStart.latitude,
          sourceLon: curStart.longitude,
          destLat: curDest.latitude,
          destLon: curDest.longitude,
          travelDate: format(selectedDate, "yyyy-MM-dd'T'HH:mm:ss"),
          requestedSeats: curSeats,
          radiusInMeters: 10000,
          page: 0,
          size: 15,
        };

        addRecentSearch({
          startLocation: curStart,
          destinationLocation: curDest,
          travelDate: format(selectedDate, "yyyy-MM-dd'T'HH:mm:ss"),
          seatCount: curSeats,
        });

        const results = await rideService.searchRides(payload);
        const ridesList = results?.rides || results?.data || (Array.isArray(results) ? results : []);
        setSearchResults(ridesList);

        if (curType === 'local') {
          navigate('LocalRideResults');
        } else {
          navigate('AvailableRides');
        }
      } catch (error: any) {
        console.error('Failed to search rides:', error);
        showNotification(
          NotificationType.ERROR,
          translate('notification.defaultErrorTitle'),
          getErrorMessage(error, translate('notification.defaultErrorMessage'))
        );
        setIsSearching(false);
      }
    }
  }, [navigate]);

  const handleSelectRecentSearch = useCallback(async (search: RecentSearch) => {
    const store = useBookRideStore.getState();
    store.setStartLocation(search.startLocation);
    store.setDestinationLocation(search.destinationLocation);
    store.setTravelDate(search.travelDate);
    store.setSeatCount(search.seatCount);

    const selectedDate = new Date(search.travelDate);
    if (isBefore(selectedDate, startOfDay(new Date()))) {
      store.setTravelDate(null);
      navigate('BookDateSelection');
    } else {
      try {
        setIsSearching(true);
        const payload: SearchRidePayload = {
          sourceLat: search.startLocation.latitude,
          sourceLon: search.startLocation.longitude,
          destLat: search.destinationLocation.latitude,
          destLon: search.destinationLocation.longitude,
          travelDate: format(selectedDate, "yyyy-MM-dd'T'HH:mm:ss"),
          requestedSeats: search.seatCount,
          radiusInMeters: 10000,
          page: 0,
          size: 15,
        };

        const results = await rideService.searchRides(payload);
        const ridesList = results?.rides || results?.data || (Array.isArray(results) ? results : []);
        store.setSearchResults(ridesList);

        if (store.rideType === 'local') {
          navigate('LocalRideResults');
        } else {
          navigate('AvailableRides');
        }
      } catch (error: any) {
        console.error('Failed to search rides from recent search:', error);
        showNotification(
          NotificationType.ERROR,
          translate('notification.defaultErrorTitle'),
          getErrorMessage(error, translate('notification.defaultErrorMessage'))
        );
        setIsSearching(false);
      }
    }
  }, [navigate]);

  const handleSetRideType = useCallback((type: 'local' | 'intercity') => {
    useBookRideStore.getState().setRideType(type);
  }, []);

  const handleClearRecentSearches = useCallback(() => {
    useBookRideStore.getState().clearRecentSearches();
  }, []);

  return {
    pickup: startLocation?.address || '',
    destination:  destinationLocation?.address || '',
    travelDate: travelDate ? new Date(travelDate) : new Date(),
    peopleCount: seatCount,
    isSearching,
    isSwapped,
    recentSearches,
    handlePressPickup,
    handlePressDestination,
    handleSwapLocations,
    handleOpenDatePicker,
    incrementPeople,
    decrementPeople,
    handleSearchRides,
    handleSelectRecentSearch,
    clearRecentSearches: handleClearRecentSearches,
    t,
    rideType,
    setRideType: handleSetRideType,
  };
};

import { useState, useCallback, useMemo } from 'react';
import { useLocale } from '@/constants/localization';
import { RideData } from './types';
import { useBookRideStore } from '@/store/useBookRideStore';
import { calculateDistance } from '@/utils/location';
import { calculateSegmentPrice } from '@/utils/pricing';
import rideService from '@/serviceManager/rideService';
import { useAppNavigation } from '@/hooks/useAppNavigation';
import { useTranslation } from '@/hooks/useTranslation';
import { showNotification } from '@/components/organisms/GlobalNotification/GlobalNotification';
import { NotificationType } from '@/constants/enums';
import { formatTimeSafely, safeParseDate } from '@/utils/date';
import { getErrorMessage } from '@/utils/error';

export const useAvailableRides = () => {
  const { navigate, goBack } = useAppNavigation();
  const { availableRides: t, rideFilters: ft } = useLocale();
  const { t: translate } = useTranslation();
  const [selectedFilters, setSelectedFilters] = useState<string[]>([]);
  const [isFilterModalOpen, setIsFilterModalOpen] = useState(false);
  const [isFetchingMore, setIsFetchingMore] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const { 
    searchResults, 
    startLocation, 
    destinationLocation, 
    hasMore,
  } = useBookRideStore();

  const mapFiltersToPayload = useCallback((activeFilters: string[]) => {
    const payload: any = {};

    if (activeFilters.includes('nearPickup')) payload.proximityType = 'PICKUP';
    if (activeFilters.includes('nearDropoff')) payload.proximityType = 'DROP_OFF';

    if (activeFilters.includes('noSmoking')) payload.noSmoking = true;
    if (activeFilters.includes('ladiesOnly')) payload.ladiesOnly = true;
    if (activeFilters.includes('verifiedOnly')) payload.verifiedDrivers = true;
    if (activeFilters.includes('petFriendly')) payload.petFriendly = true;
    if (activeFilters.includes('luggageAllowed')) payload.luggageAllowed = true;

    const timeFilters = activeFilters.filter(f => f.startsWith('time_'));
    if (timeFilters.length > 0) {
      const slots = timeFilters.map(f => {
        const [_, s, e] = f.split('_').map(Number);
        return { s, e };
      }).sort((a, b) => a.s - b.s);

      const merged: string[] = [];
      let current = slots[0];

      for (let i = 1; i < slots.length; i++) {
        if (slots[i].s === current.e) {
          current.e = slots[i].e;
        } else {
          merged.push(`${current.s === 0 ? 12 : (current.s > 12 ? current.s - 12 : current.s)}-${current.e > 12 ? current.e - 12 : (current.e === 0 ? 12 : current.e)} ${current.e <= 12 ? 'AM' : 'PM'}`);
          current = slots[i];
        }
      }
      merged.push(`${current.s === 0 ? 12 : (current.s > 12 ? current.s - 12 : current.s)}-${current.e > 12 ? current.e - 12 : (current.e === 0 ? 12 : (current.e === 24 ? 12 : current.e))} ${current.e <= 12 ? 'AM' : (current.e === 24 ? 'AM' : 'PM')}`);
      payload.departureTimeSlot = merged.join(', ');
    }

    return payload;
  }, []);

  const handleLoadMore = useCallback(async () => {
    const store = useBookRideStore.getState();
    const { startLocation: curStart, destinationLocation: curDest, travelDate: curDate, currentPage, hasMore: curHasMore, seatCount } = store;

    if (isFetchingMore || !curHasMore || !curStart || !curDest || !curDate) return;

    try {
      setIsFetchingMore(true);
      const nextPage = currentPage + 1;

      const payload = {
        sourceLat: curStart.latitude,
        sourceLon: curStart.longitude,
        destLat: curDest.latitude,
        destLon: curDest.longitude,
        travelDate: curDate,
        requestedSeats: seatCount,
        radiusInMeters: 10000,
        page: nextPage,
        size: 10,
        ...mapFiltersToPayload(selectedFilters)
      };

      const response = await rideService.searchRides(payload);
      const newRides = response?.rides || response?.data || (Array.isArray(response) ? response : []);

      if (newRides && newRides.length > 0) {
        store.appendSearchResults(newRides);
        store.setCurrentPage(nextPage);
      }
    } catch (error: any) {
      console.error('Failed to load more rides:', error);
      showNotification(
        NotificationType.ERROR,
        translate('notification.defaultErrorTitle'),
        getErrorMessage(error, translate('notification.defaultErrorMessage'))
      );
    } finally {
      setIsFetchingMore(false);
    }
  }, [isFetchingMore, selectedFilters, mapFiltersToPayload]);

  const mappedRides: RideData[] = useMemo(() => {
    if (!searchResults || !Array.isArray(searchResults) || searchResults.length === 0) return [];

    return searchResults
      .filter(Boolean)
      .map((ride, index) => {
      const hasStops = ride.stops && ride.stops.length > 0;
      const firstStop = hasStops ? ride.stops[0] : null;
      const lastStop = hasStops ? ride.stops[ride.stops.length - 1] : null;

      const totalPrice = hasStops 
        ? calculateSegmentPrice(ride.stops || [], ride.fullJourneyPrice)
        : (ride.price || 0);

      const features: string[] = [];
      if (ride.preferences?.nonSmoking) features.push('noSmoking');
      if (ride.preferences?.womenOnly) features.push('ladiesOnly');
      if (ride.preferences?.petFriendly) features.push('petFriendly');
      if (ride.preferences?.luggageAllowed) features.push('luggageAllowed');
      if (ride.preferences?.manualApproval === false) features.push('autoApproval');
      if (ride.preferences?.musicPreference) features.push(`music:${ride.preferences.musicPreference}`);

      const sLat = hasStops ? firstStop?.lat : (ride.sourceLat || 0);
      const sLon = hasStops ? firstStop?.lon : (ride.sourceLon || 0);
      const dLat = hasStops ? lastStop?.lat : (ride.destLat || 0);
      const dLon = hasStops ? lastStop?.lon : (ride.destLon || 0);

      const pickupDistance = startLocation 
        ? calculateDistance(startLocation.latitude, startLocation.longitude, sLat, sLon)
        : 9999;

      const dropoffDistance = destinationLocation
        ? calculateDistance(destinationLocation.latitude, destinationLocation.longitude, dLat, dLon)
        : 9999;

      const timeline = hasStops 
        ? ride.stops.map((stop: any, idx: number, arr: any[]) => ({
            time: formatTimeSafely(stop.arrivalTime),
            location: stop.name || stop.address || 'Unknown Location',
            type: idx === 0 ? 'pickup' : (idx === arr.length - 1 ? 'destination' : 'stop'),
          }))
        : [
            {
              time: formatTimeSafely(ride.startTime),
              location: ride.sourceStopName || ride.sourceAddress || 'Pickup',
              type: 'pickup'
            },
            {
              time: formatTimeSafely(ride.endTime),
              location: ride.destinationStopName || ride.destinationAddress || 'Dropoff',
              type: 'destination'
            }
          ];

      const sTime = ride.startTime || firstStop?.arrivalTime;
      const eTime = ride.endTime || lastStop?.arrivalTime;

      return {
        id: ride.id || String(index),
        driver: {
          name: ride.driverName || 'Unknown Host',
          rating: ride.driverRating || 4.8,
          rideCount: ride.driverRideCount || 15,
          avatar: ride.driverPhotoUrl || 'https://ui-avatars.com/api/?name=' + (ride.driverName || 'U'),
          driverPhotoUrl: ride.driverPhotoUrl,
          isVerified: true,
        },
        price: totalPrice,
        timeline,
        features,
        seatsLeft: ride.availableSeats,
        isFrequentCoRider: !!ride.isFrequentCoRider,
        pickupDistance,
        dropoffDistance,
        totalDuration: (() => {
          const start = safeParseDate(sTime);
          const end = safeParseDate(eTime);
          return start && end ? Math.round((end.getTime() - start.getTime()) / (1000 * 60)) : 0;
        })(),
        departureHour: sTime ? (safeParseDate(sTime)?.getHours() ?? undefined) : undefined,
        sourceStopId: ride.sourceStopId,
        destinationStopId: ride.destinationStopId,
      } as any;
    });
  }, [searchResults, startLocation, destinationLocation]);

  const filteredRides = useMemo(() => {
    let result = [...mappedRides];

    if (selectedFilters.length > 0) {
      const timeFilters = selectedFilters.filter(f => f.startsWith('time_'));

      if (timeFilters.length > 0) {
        result = result.filter((ride) => {
          if (ride.departureHour === undefined) return false;
          return timeFilters.some((slot) => {
            const [_, start, end] = slot.split('_').map(Number);
            return ride.departureHour! >= start && ride.departureHour! < end;
          });
        });
      }
    }

    if (selectedFilters.includes('time')) {
      result.sort((a, b) => {
        const timeA = a.timeline[0]?.time || 'TBD';
        const timeB = b.timeline[0]?.time || 'TBD';
        return timeA.localeCompare(timeB);
      });
    }

    if (selectedFilters.includes('nearPickup')) {
      result.sort((a, b) => (a.pickupDistance || 0) - (b.pickupDistance || 0));
    }

    if (selectedFilters.includes('nearDropoff')) {
      result.sort((a, b) => (a.dropoffDistance || 0) - (b.dropoffDistance || 0));
    }

    return result;
  }, [mappedRides, selectedFilters]);

  const handleBack = useCallback(() => {
    goBack();
  }, [goBack]);

  const handleRideSelect = useCallback((rideId: string) => {
    const rawRides = useBookRideStore.getState().searchResults;
    const ride = rawRides?.find(r => String(r.id) === String(rideId));
    navigate('RideInformation', { 
      rideId,
      sourceStopId: ride?.sourceStopId,
      destinationStopId: ride?.destinationStopId
    });
  }, [navigate]);

  const handleOpenFilters = useCallback(() => {
    setIsFilterModalOpen(true);
  }, []);

  const handleCloseFilters = useCallback(() => {
    setIsFilterModalOpen(false);
  }, []);

  const toggleFilter = useCallback((filter: string) => {
    setSelectedFilters(prev => {
      const isAlreadySelected = prev.includes(filter);

      if (isAlreadySelected) {
        return prev.filter(f => f !== filter);
      } else {
        if (filter === 'nearPickup') {
          return [...prev.filter(f => f !== 'nearDropoff'), 'nearPickup'];
        }
        if (filter === 'nearDropoff') {
          return [...prev.filter(f => f !== 'nearPickup'), 'nearDropoff'];
        }
        return [...prev, filter];
      }
    });
  }, []);

  const handleClearFilters = useCallback(async () => {
    setSelectedFilters([]);
    const store = useBookRideStore.getState();
    store.setFilters({});
    setIsFilterModalOpen(false);

    const { startLocation: curStart, destinationLocation: curDest, travelDate: curDate, seatCount, setSearchResults } = store;
    if (!curStart || !curDest || !curDate) return;

    setSearchResults([]);
    setIsLoading(true);
    try {
      const payload = {
        sourceLat: curStart.latitude,
        sourceLon: curStart.longitude,
        destLat: curDest.latitude,
        destLon: curDest.longitude,
        travelDate: curDate,
        requestedSeats: seatCount,
        radiusInMeters: 10000,
        page: 0,
        size: 10,
      };
      const response = await rideService.searchRides(payload);
      const ridesList = response?.rides || response?.data || (Array.isArray(response) ? response : []);
      setSearchResults(ridesList);
    } catch (error: any) {
      console.error('Failed to clear filters and fetch:', error);
      showNotification(
        NotificationType.ERROR,
        translate('notification.defaultErrorTitle'),
        getErrorMessage(error, translate('notification.defaultErrorMessage'))
      );
    } finally {
      setIsLoading(false);
    }
  }, []);

  const handleApplyFilters = useCallback(async (filters: string[]) => {
    const isSame = 
      filters.length === selectedFilters.length && 
      filters.every(f => selectedFilters.includes(f));

    if (isSame) {
      return;
    }

    setSelectedFilters(filters);
    const store = useBookRideStore.getState();
    const { startLocation: curStart, destinationLocation: curDest, travelDate: curDate, seatCount, setSearchResults } = store;
    if (!curStart || !curDest || !curDate) return;

    setSearchResults([]);
    setIsLoading(true);
    try {
      const filterPayload = mapFiltersToPayload(filters);
      const payload = {
        sourceLat: curStart.latitude,
        sourceLon: curStart.longitude,
        destLat: curDest.latitude,
        destLon: curDest.longitude,
        travelDate: curDate,
        requestedSeats: seatCount,
        radiusInMeters: 10000,
        page: 0,
        size: 10,
        ...filterPayload
      };

      const response = await rideService.searchRides(payload);
      const ridesList = response?.rides || response?.data || (Array.isArray(response) ? response : []);
      setSearchResults(ridesList);
    } catch (error: any) {
      console.error('Failed to apply filters:', error);
      showNotification(
        NotificationType.ERROR,
        translate('notification.defaultErrorTitle'),
        getErrorMessage(error, translate('notification.defaultErrorMessage'))
      );
    } finally {
      setIsLoading(false);
    }
  }, [mapFiltersToPayload, selectedFilters]);

  const handleViewDetails = useCallback((rideId: string) => {
    console.log('Viewing details:', rideId);
  }, []);

  return {
    mockRides: filteredRides,
    selectedFilters,
    isFilterModalOpen,
    isFetchingMore,
    toggleFilter,
    handleOpenFilters,
    handleCloseFilters,
    handleClearFilters,
    handleApplyFilters,
    handleBack,
    handleRideSelect,
    handleViewDetails,
    handleLoadMore,
    isLoading,
    hasMore,
    t,
    ft,
  };
};

import { Location } from '@/store/useLocationStore';

export interface LocalRideResultsProps {}

export interface ViewState {
  latitude: number;
  longitude: number;
}

import { useMemo } from 'react';
import { RideData } from '@/screens/BookFlow/3_AvailableRides/types';
import { calculateDistance } from '@/utils/location';
import { formatTimeSafely, formatDateSafely } from '@/utils/date';

export const mapBackendRideToUI = (
  rideRaw: any,
  startLocation?: any,
  destinationLocation?: any,
  sourceStopId?: number,
  destinationStopId?: number
) => {
  if (!rideRaw) return null;

  const features: string[] = [];
  if (rideRaw.preferences?.nonSmoking) features.push('noSmoking');
  if (rideRaw.preferences?.womenOnly) features.push('ladiesOnly');
  if (rideRaw.preferences?.petFriendly) features.push('petFriendly');
  if (rideRaw.preferences?.luggageAllowed) features.push('luggageAllowed');

  if (rideRaw.requestType === 'review' || rideRaw.preferences?.manualApproval === true) {
    features.push('manualApproval');
  } else if (rideRaw.requestType === 'instant' || rideRaw.preferences?.manualApproval === false) {
    features.push('autoApproval');
  }

  if (rideRaw.preferences?.musicPreference) features.push(`music:${rideRaw.preferences.musicPreference}`);

  const firstStop = rideRaw.stops?.[0];
  const lastStop = rideRaw.stops?.[rideRaw.stops.length - 1];

  const pickupDistance = (startLocation && firstStop)
    ? calculateDistance(startLocation.latitude, startLocation.longitude, firstStop.lat, firstStop.lon)
    : undefined;

  const dropoffDistance = (destinationLocation && lastStop)
    ? calculateDistance(destinationLocation.latitude, destinationLocation.longitude, lastStop.lat, lastStop.lon)
    : undefined;

  const stops = rideRaw.stops || [];
  const sourceIdx = stops.findIndex((s: any) => s.id === sourceStopId);
  const destIdx = stops.findIndex((s: any) => s.id === destinationStopId);
  const [startIdx, endIdx] = [sourceIdx, destIdx].sort((a, b) => a - b);

  const timeline = stops.map((stop: any, idx: number, arr: any[]) => {
    const isHighlighted = stop.id === sourceStopId || stop.id === destinationStopId;
    const address = stop.stopName || stop.name || 'Unknown';
    let displayLocation = address;
    const isBetweenOrAt = idx >= startIdx && idx <= endIdx && startIdx !== -1 && endIdx !== -1;

    const isDriverRole = rideRaw.userRole === 'DRIVER';

    // Only truncate if NOT highlighted AND NOT driver
    if (!isHighlighted && !isDriverRole) {
      const parts = address.split(',').map((p: string) => p.trim());
      if (parts.length >= 4) {
        displayLocation = parts[parts.length - 4];
      } else if (parts.length >= 3) {
        displayLocation = parts[parts.length - 3];
      } else {
        displayLocation = parts[0] || '';
      }
    }

    let durationSincePrevious = '';
    if (idx > 0) {
      const prevStop = arr[idx - 1];
      if (prevStop.arrivalTime && stop.arrivalTime) {
        const diffMins = Math.round((new Date(stop.arrivalTime).getTime() - new Date(prevStop.arrivalTime).getTime()) / (1000 * 60));
        const h = Math.floor(diffMins / 60);
        const m = diffMins % 60;
        durationSincePrevious = h > 0 ? `${h}h${m > 0 ? m : ''}` : `${m}m`;
      }
    }

    return {
      id: stop.id,
      time: formatTimeSafely(stop.arrivalTime),
      durationSincePrevious,
      location: displayLocation,
      type: idx === 0 ? 'pickup' : (idx === arr.length - 1 ? 'destination' : 'stop'),
      description: isHighlighted ? (idx === 0 ? 'Pickup' : (idx === arr.length - 1 ? 'Dropoff' : 'Stop')) : '',
      isHighlighted,
    };
  });

  let totalDurationMins = 0;
  if (rideRaw.duration) {
    const hMatch = rideRaw.duration.match(/(\d+)h/);
    const mMatch = rideRaw.duration.match(/(\d+)m/);
    if (hMatch) totalDurationMins += parseInt(hMatch[1]) * 60;
    if (mMatch) totalDurationMins += parseInt(mMatch[1]);
  }

  return {
    id: rideRaw.id,
    driver: {
      id: (rideRaw.user || rideRaw.driver)?.id,
      name: (rideRaw.user || rideRaw.driver)?.name || 'Unknown Driver',
      rating: (rideRaw.user || rideRaw.driver)?.rating || 4.8,
      rideCount: 15,
      avatar: (rideRaw.user || rideRaw.driver)?.photoUrl || 'https://ui-avatars.com/api/?name=' + ((rideRaw.user || rideRaw.driver)?.name || 'U'),
      driverPhotoUrl: (rideRaw.user || rideRaw.driver)?.photoUrl,
      isVerified: !!(rideRaw.user || rideRaw.driver)?.verified,
      bio: (rideRaw.user || rideRaw.driver)?.bio,
    },
    price: rideRaw.price || 0,
    timeline,
    features,
    seatsLeft: rideRaw.availableSeats || 0,
    isFrequentCoRider: false,
    pickupDistance,
    dropoffDistance,
    departureHour: firstStop?.arrivalTime ? new Date(firstStop.arrivalTime).getHours() : undefined,
    vehicle: {
      registration: rideRaw.vehicle?.plateNumber || 'UP-16-AX-0000',
      model: rideRaw.vehicle?.model,
      color: rideRaw.vehicle?.color,
      type: rideRaw.vehicle?.type,
      company: rideRaw.vehicle?.company,
    },
    totalDistance: rideRaw.stops?.reduce((acc: number, stop: any, idx: number, arr: any[]) => {
      if (stop.distanceFromPreviousStop !== undefined) {
        return acc + stop.distanceFromPreviousStop;
      }
      if (idx > 0) {
        const prev = arr[idx - 1];
        return acc + calculateDistance(prev.lat, prev.lon, stop.lat, stop.lon);
      }
      return acc;
    }, 0) || 0,
    totalDuration: totalDurationMins,
    routePath: rideRaw.routePath,
    seats: rideRaw.seats || [],
    passengers: (rideRaw.passengers || []).map((p: any) => ({
      ...p,
      id: p.passengerId,
      name: p.name,
      photoUrl: p.photoUrl,
    })),
    departureDate: formatDateSafely(firstStop?.arrivalTime, {
      weekday: 'short',
      day: 'numeric',
      month: 'short',
    }, 'Today'),
    departureTime: formatTimeSafely(firstStop?.arrivalTime, {
      hour: 'numeric',
      minute: '2-digit',
      hour12: true,
    }, '--:--'),
    rawStops: stops.map((s: any) => ({
      lat: s.lat,
      lon: s.lon,
      name: s.stopName || s.name,
      sequence: s.sequence,
      arrivalTime: s.arrivalTime,
      id: s.id,
    })),
    userRole: rideRaw.userRole,
    bookingPrice: rideRaw.myBooking?.price ?? rideRaw.price ?? 0,
    seatsBooked: rideRaw.myBooking?.seatsBooked ?? 0,
    seatNames: rideRaw.myBooking?.seatNames ?? [],
    paymentMethod: rideRaw.paymentMethod ?? 'Cash',
    myBookingId: rideRaw.myBooking?.bookingId ?? null,
    status: rideRaw.status,
    cancellationReason: rideRaw.cancellationReason,
  } as any;
};

export const useRideDataMapper = (
  rideRaw: any,
  startLocation: any,
  destinationLocation: any,
  sourceStopId?: number,
  destinationStopId?: number
) => {
  return useMemo(() =>
    mapBackendRideToUI(rideRaw, startLocation, destinationLocation, sourceStopId, destinationStopId),
    [rideRaw, startLocation, destinationLocation, sourceStopId, destinationStopId]
  );
};

import { useCallback, useState, useEffect } from 'react';
import { Alert, Clipboard, Linking, Platform } from 'react-native';
import { useLocale } from '@/constants/localization';
import { useBookRideStore } from '@/store/useBookRideStore';
import rideService from '@/serviceManager/rideService';
import { useRideDataMapper } from './useRideDataMapper';
import { useAppNavigation } from '@/hooks/useAppNavigation';
import { showNotification } from '@/components/organisms/GlobalNotification/GlobalNotification';
import { NotificationType } from '@/constants/enums';
import { getErrorMessage } from '@/utils/error';

export const useRideInformation = (rideId: string, sourceStopId?: number, destinationStopId?: number) => {
  const { navigate, goBack } = useAppNavigation();
  const { rideInformation: t } = useLocale();
  const locale = useLocale();
  const [rideRaw, setRideRaw] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);

  const [isReportModalVisible, setIsReportModalVisible] = useState(false);

  const handleReportRide = useCallback(() => {
    setIsReportModalVisible(true);
  }, []);

  const handleReportSubmit = useCallback((_data: { categoryId: string; description: string }) => {
    setIsReportModalVisible(false);
    showNotification(
      NotificationType.SUCCESS,
      locale.rideDetails.reportSuccessTitle,
      locale.rideDetails.reportSuccessMessage
    );
  }, [locale]);

  const startLocation = useBookRideStore(state => state.startLocation);
  const destinationLocation = useBookRideStore(state => state.destinationLocation);

  useEffect(() => {
    const fetchDetail = async () => {
      try {
        setIsLoading(true);
        const data = await rideService.getRideDetail(rideId, sourceStopId, destinationStopId);
        setRideRaw(data);
      } catch (error: any) {
        console.error('Failed to fetch ride detail:', error);
        showNotification(
          NotificationType.ERROR,
          locale.notification.defaultErrorTitle,
          getErrorMessage(error, locale.notification.defaultErrorMessage)
        );
      } finally {
        setTimeout(() => setIsLoading(false), 300);
      }
    };
    fetchDetail();
  }, [rideId, sourceStopId, destinationStopId]);

  const ride = useRideDataMapper(
    rideRaw, 
    startLocation, 
    destinationLocation, 
    sourceStopId, 
    destinationStopId
  );

  const handleBack = useCallback(() => {
    goBack();
  }, [goBack]);

  const handleBook = useCallback(() => {
    navigate('BookSeatSelection', { 
      rideId,
      sourceStopId,
      destinationStopId,
      seats: (ride as any)?.seats,
      passengers: (ride as any)?.passengers,
      vehicleType: (ride as any)?.vehicle?.type,
      departureDate: (ride as any)?.departureDate,
      departureTime: (ride as any)?.departureTime,
    });
  }, [navigate, rideId, sourceStopId, destinationStopId, ride]);

  const handleChat = useCallback(() => {
    navigate('ChatDetails', {
      userId: ride?.driver?.id,
      rideId: rideId,
      name: ride?.driver?.name,
      avatarUri: ride?.driver?.avatar,
      rideInfo: {
        pickup: ride?.timeline?.[0]?.location || '',
        dropoff: ride?.timeline?.[ride?.timeline.length - 1]?.location || '',
        date: ride?.departureDate || '',
        time: ride?.departureTime || '',
      },
    });
  }, [navigate, ride, rideId]);

  const handleViewRoute = useCallback((index?: number) => {
    const stops = ride?.rawStops;
    if (!stops || stops.length === 0) return;
    navigate('RideRouteMap', {
      routePath: ride?.routePath ?? '',
      stops,
      initialStopIndex: index,
      sourceStopId,
      destinationStopId,
      userSearchedPickup: startLocation ? {
        latitude: startLocation.latitude,
        longitude: startLocation.longitude,
        name: startLocation.name || startLocation.address || 'Pickup Point',
      } : undefined,
      userSearchedDropoff: destinationLocation ? {
        latitude: destinationLocation.latitude,
        longitude: destinationLocation.longitude,
        name: destinationLocation.name || destinationLocation.address || 'Dropoff Point',
      } : undefined,
    });
  }, [navigate, ride, sourceStopId, destinationStopId, startLocation, destinationLocation]);

  const handleCopyAddress = useCallback((address: string) => {
    Clipboard.setString(address);
  }, []);

  const handleExternalMapOpen = useCallback((lat?: number, lon?: number, label?: string) => {
    if (!lat || !lon) return;
    const url = Platform.select({
      ios: `maps:0,0?q=${label || 'Location'}@${lat},${lon}`,
      android: `geo:0,0?q=${lat},${lon}(${label || 'Location'})`,
    }) || `https://www.google.com/maps/search/?api=1&query=${lat},${lon}`;

    Linking.openURL(url).catch(() => {
      showNotification(
        NotificationType.ERROR,
        locale.notification.defaultErrorTitle,
        locale.notification.mapOpenError
      );
    });
  }, [locale]);

  const handleDriverProfile = useCallback(() => {
    if (ride?.driver?.id) {
      navigate('UserProfileDetail', { userId: ride?.driver?.id });
    }
  }, [navigate, ride]);

  const handlePassengerProfile = useCallback((id: string) => {
    navigate('UserProfileDetail', { userId: id });
  }, [navigate]);

  return {
    t,
    handleBack,
    handleBook,
    handleChat,
    handleDriverProfile,
    handlePassengerProfile,
    handleViewRoute,
    handleCopyAddress,
    handleExternalMapOpen,
    ride,
    isLoading,
    isReportModalVisible,
    setIsReportModalVisible,
    handleReportRide,
    handleReportSubmit,
  };
};

import { useCallback, useMemo, useState, useRef, useEffect } from 'react';
import { Linking } from 'react-native';
import { useAppNavigation } from '@/hooks/useAppNavigation';
import { CameraRef } from '@maplibre/maplibre-react-native';
import { decodePolyline, getBoundingBox } from '@/utils/polyline';
import { locationService } from '@/serviceManager/locationService';

const findClosestCoordinateIndex = (pt: [number, number], coords: [number, number][]) => {
  let closestIndex = 0;
  let minDistance = Infinity;
  for (let i = 0; i < coords.length; i++) {
    const dx = coords[i][0] - pt[0];
    const dy = coords[i][1] - pt[1];
    const distance = dx * dx + dy * dy;
    if (distance < minDistance) {
      minDistance = distance;
      closestIndex = i;
    }
  }
  return closestIndex;
};

export const useRideRouteMap = (
  routePath?: string, 
  stops?: any[], 
  destination?: any, 
  initialStopIndex?: number,
  sourceStopId?: number | string,
  destinationStopId?: number | string,
  userSearchedPickup?: { latitude: number; longitude: number; name: string },
  userSearchedDropoff?: { latitude: number; longitude: number; name: string }
) => {
  const { pop } = useAppNavigation();
  const cameraRef = useRef<CameraRef>(null);
  const mapRef = useRef<any>(null);
  const zoomRef = useRef(14);

  const [currentUserLocation, setCurrentUserLocation] = useState<[number, number] | null>(null);
  const [pickupRouteCoords, setPickupRouteCoords] = useState<[number, number][]>([]);
  const [dropoffRouteCoords, setDropoffRouteCoords] = useState<[number, number][]>([]);

  const ridePickup = useMemo(() => {
    return (stops || []).find(s => String(s.id) === String(sourceStopId));
  }, [stops, sourceStopId]);

  const rideDropoff = useMemo(() => {
    return (stops || []).find(s => String(s.id) === String(destinationStopId));
  }, [stops, destinationStopId]);

  // Fetch connection routes
  useEffect(() => {
    let active = true;
    const fetchDirections = async () => {
      // 1. Fetch Pickup Connection Route (Searched Pickup -> Ride Pickup)
      if (userSearchedPickup && ridePickup) {
        try {
          const routes = await locationService.getDirections(
            userSearchedPickup.latitude,
            userSearchedPickup.longitude,
            ridePickup.lat,
            ridePickup.lon
          );
          if (active && routes && routes.length > 0) {
            const polyline = routes[0].overview_polyline || routes[0].geometry || '';
            const coords = decodePolyline(polyline, 1e5);
            if (coords && coords.length > 0) {
              setPickupRouteCoords(coords);
            } else {
              setPickupRouteCoords([
                [userSearchedPickup.longitude, userSearchedPickup.latitude],
                [ridePickup.lon, ridePickup.lat]
              ]);
            }
          } else if (active) {
            setPickupRouteCoords([
              [userSearchedPickup.longitude, userSearchedPickup.latitude],
              [ridePickup.lon, ridePickup.lat]
            ]);
          }
        } catch (err) {
          console.error('Failed to fetch pickup connection directions:', err);
          if (active) {
            setPickupRouteCoords([
              [userSearchedPickup.longitude, userSearchedPickup.latitude],
              [ridePickup.lon, ridePickup.lat]
            ]);
          }
        }
      }

      // 2. Fetch Dropoff Connection Route (Ride Dropoff -> Searched Dropoff)
      if (userSearchedDropoff && rideDropoff) {
        try {
          const routes = await locationService.getDirections(
            rideDropoff.lat,
            rideDropoff.lon,
            userSearchedDropoff.latitude,
            userSearchedDropoff.longitude
          );
          if (active && routes && routes.length > 0) {
            const polyline = routes[0].overview_polyline || routes[0].geometry || '';
            const coords = decodePolyline(polyline, 1e5);
            if (coords && coords.length > 0) {
              setDropoffRouteCoords(coords);
            } else {
              setDropoffRouteCoords([
                [rideDropoff.lon, rideDropoff.lat],
                [userSearchedDropoff.longitude, userSearchedDropoff.latitude]
              ]);
            }
          } else if (active) {
            setDropoffRouteCoords([
              [rideDropoff.lon, rideDropoff.lat],
              [userSearchedDropoff.longitude, userSearchedDropoff.latitude]
            ]);
          }
        } catch (err) {
          console.error('Failed to fetch dropoff connection directions:', err);
          if (active) {
            setDropoffRouteCoords([
              [rideDropoff.lon, rideDropoff.lat],
              [userSearchedDropoff.longitude, userSearchedDropoff.latitude]
            ]);
          }
        }
      }
    };

    fetchDirections();
    return () => {
      active = false;
    };
  }, [userSearchedPickup, userSearchedDropoff, ridePickup, rideDropoff]);

  const initialPoint = useMemo(() => {
    if (destination) return { lat: destination.latitude, lon: destination.longitude };
    if (initialStopIndex !== undefined && stops && stops[initialStopIndex]) return stops[initialStopIndex];
    return (stops && stops.length > 0) ? stops[0] : { lat: 12.9716, lon: 77.5946 };
  }, [destination, initialStopIndex, stops]);

  const [zoom, setZoom] = useState(initialStopIndex !== undefined || destination ? 15 : 12);
  const [region, setRegion] = useState({
    latitude: initialPoint?.lat || 12.9716,
    longitude: initialPoint?.lon || 77.5946,
  });

  const [isMapMounted, setIsMapMounted] = useState(true);

  const handleBack = useCallback(() => {
    pop();
  }, [pop]);

  const handleUserLocationUpdate = useCallback((location: any) => {
    if (location?.coords) {
      setCurrentUserLocation([location.coords.longitude, location.coords.latitude]);
    }
  }, []);

  const handleRegionDidChange = useCallback((event: any) => {
    const viewState = event?.nativeEvent || event;
    if (!viewState?.center) return;
    const [longitude, latitude] = viewState.center;
    const currentZoom = viewState.zoom;

    if (currentZoom !== undefined) {
      setZoom(currentZoom);
      zoomRef.current = currentZoom;
    }
    setRegion({ latitude, longitude });
  }, []);

  const handleZoom = useCallback((increment: number) => {
    const newZoom = Math.min(Math.max(zoomRef.current + increment, 3), 20);
    zoomRef.current = newZoom;
    cameraRef.current?.setStop({ zoom: newZoom, duration: 300 });
  }, []);

  const handleZoomIn = useCallback(() => handleZoom(1), [handleZoom]);
  const handleZoomOut = useCallback(() => handleZoom(-1), [handleZoom]);

  const handleOpenExternalMap = useCallback((type: 'google' | 'apple') => {
    let originLat: number | undefined;
    let originLon: number | undefined;
    let destLat: number | undefined;
    let destLon: number | undefined;

    const clickedStop = (initialStopIndex !== undefined && stops && stops[initialStopIndex]) ? stops[initialStopIndex] : null;
    const isPickup = clickedStop && String(clickedStop.id) === String(sourceStopId);
    const isDropoff = clickedStop && String(clickedStop.id) === String(destinationStopId);

    if (isPickup && userSearchedPickup && ridePickup) {
      originLat = userSearchedPickup.latitude;
      originLon = userSearchedPickup.longitude;
      destLat = ridePickup.lat;
      destLon = ridePickup.lon;
    } else if (isDropoff && userSearchedDropoff && rideDropoff) {
      originLat = rideDropoff.lat;
      originLon = rideDropoff.lon;
      destLat = userSearchedDropoff.latitude;
      destLon = userSearchedDropoff.longitude;
    } else {
      destLat = initialPoint?.lat;
      destLon = initialPoint?.lon;
      if (currentUserLocation) {
        originLon = currentUserLocation[0];
        originLat = currentUserLocation[1];
      }
    }

    if (!destLat || !destLon) return;

    let url = '';
    if (type === 'apple') {
      if (originLat !== undefined && originLon !== undefined) {
        url = `http://maps.apple.com/?saddr=${originLat},${originLon}&daddr=${destLat},${destLon}&dirflg=d`;
      } else {
        url = `http://maps.apple.com/?daddr=${destLat},${destLon}&dirflg=d`;
      }
    } else {
      if (originLat !== undefined && originLon !== undefined) {
        url = `https://www.google.com/maps/dir/?api=1&origin=${originLat},${originLon}&destination=${destLat},${destLon}&travelmode=driving`;
      } else {
        url = `https://www.google.com/maps/dir/?api=1&destination=${destLat},${destLon}&travelmode=driving`;
      }
    }

    Linking.openURL(url).catch(err => console.error("Couldn't load maps", err));
  }, [initialStopIndex, stops, sourceStopId, destinationStopId, userSearchedPickup, userSearchedDropoff, ridePickup, rideDropoff, initialPoint, currentUserLocation]);

  const mapData = useMemo(() => {
    let coordinates: [number, number][] = [];
    let stopMarkers: any[] = [];

    if (destination) {
      const destCoord: [number, number] = [destination.longitude, destination.latitude];
      stopMarkers = [{
        id: 'shared-destination',
        type: 'Feature',
        properties: { type: 'marker', role: 'end', name: destination.name },
        geometry: { type: 'Point', coordinates: destCoord },
      }];
      coordinates = currentUserLocation ? [currentUserLocation, destCoord] : [destCoord];
    } else {
      const decoded = (routePath && routePath.length > 0) ? decodePolyline(routePath, 1e5) : [];
      coordinates = decoded.length > 0 ? decoded : (stops || []).map(s => [s.lon, s.lat]);

      stopMarkers = (stops || []).map((stop, idx) => {
        let role = 'stop';
        if (sourceStopId !== undefined && destinationStopId !== undefined) {
          /** Use loose equality (==) to handle string/number ID mismatches from API */
          if (String(stop.id) === String(sourceStopId)) role = 'start';
          else if (String(stop.id) === String(destinationStopId)) role = 'end';
        } else {
          role = idx === 0 ? 'start' : (idx === (stops || []).length - 1 ? 'end' : 'stop');
        }

        return {
          id: `stop-${stop.sequence}-${idx}`,
          type: 'Feature',
          properties: { 
            type: 'marker', 
            role,
            name: stop.name,
          },
          geometry: { type: 'Point', coordinates: [stop.lon, stop.lat] },
        };
      });
    }

    const showPickup = initialStopIndex === undefined || 
      (initialStopIndex !== undefined && stops && stops[initialStopIndex] && String(stops[initialStopIndex].id) === String(sourceStopId));

    const showDropoff = initialStopIndex === undefined || 
      (initialStopIndex !== undefined && stops && stops[initialStopIndex] && String(stops[initialStopIndex].id) === String(destinationStopId));

    const boundsCoords = [...coordinates];
    if (showPickup && userSearchedPickup) {
      boundsCoords.push([userSearchedPickup.longitude, userSearchedPickup.latitude]);
    }
    if (showDropoff && userSearchedDropoff) {
      boundsCoords.push([userSearchedDropoff.longitude, userSearchedDropoff.latitude]);
    }

    const bounds = boundsCoords.length > 0 ? getBoundingBox(boundsCoords) : null;

    // Split polyline coordinates into highlighted and unselected features
    const routeFeatures: any[] = [];

    if (!destination && sourceStopId !== undefined && destinationStopId !== undefined && coordinates.length > 1) {
      const pickupStop = (stops || []).find(s => String(s.id) === String(sourceStopId));
      const dropoffStop = (stops || []).find(s => String(s.id) === String(destinationStopId));

      if (pickupStop && dropoffStop) {
        const pickupIdx = findClosestCoordinateIndex([pickupStop.lon, pickupStop.lat], coordinates);
        const dropoffIdx = findClosestCoordinateIndex([dropoffStop.lon, dropoffStop.lat], coordinates);

        const [startIdx, endIdx] = [pickupIdx, dropoffIdx].sort((a, b) => a - b);

        const startCoords = coordinates.slice(0, startIdx + 1);
        const highlightedCoords = coordinates.slice(startIdx, endIdx + 1);
        const endCoords = coordinates.slice(endIdx);

        if (startCoords.length > 1) {
          routeFeatures.push({
            type: 'Feature',
            properties: { type: 'route', status: 'unselected' },
            geometry: { type: 'LineString', coordinates: startCoords },
          });
        }

        if (highlightedCoords.length > 1) {
          routeFeatures.push({
            type: 'Feature',
            properties: { type: 'route', status: 'highlighted' },
            geometry: { type: 'LineString', coordinates: highlightedCoords },
          });
        }

        if (endCoords.length > 1) {
          routeFeatures.push({
            type: 'Feature',
            properties: { type: 'route', status: 'unselected' },
            geometry: { type: 'LineString', coordinates: endCoords },
          });
        }
      } else {
        // Fallback: no matching pickup/dropoff stops found, highlight entire route
        routeFeatures.push({
          type: 'Feature',
          properties: { type: 'route', status: 'highlighted' },
          geometry: { type: 'LineString', coordinates: coordinates },
        });
      }
    } else if (coordinates.length > 1) {
      routeFeatures.push({
        type: 'Feature',
        properties: { type: 'route', status: 'highlighted' },
        geometry: { type: 'LineString', coordinates: coordinates },
      });
    }

    if (showPickup && pickupRouteCoords.length > 1) {
      routeFeatures.push({
        type: 'Feature',
        properties: { type: 'connection', status: 'pickup' },
        geometry: { type: 'LineString', coordinates: pickupRouteCoords },
      });
    }

    if (showDropoff && dropoffRouteCoords.length > 1) {
      routeFeatures.push({
        type: 'Feature',
        properties: { type: 'connection', status: 'dropoff' },
        geometry: { type: 'LineString', coordinates: dropoffRouteCoords },
      });
    }

    if (showPickup && userSearchedPickup) {
      stopMarkers.push({
        id: 'user-searched-pickup',
        type: 'Feature',
        properties: { 
          type: 'marker', 
          role: 'user-pickup',
          name: userSearchedPickup.name,
        },
        geometry: { type: 'Point', coordinates: [userSearchedPickup.longitude, userSearchedPickup.latitude] },
      });
    }

    if (showDropoff && userSearchedDropoff) {
      stopMarkers.push({
        id: 'user-searched-dropoff',
        type: 'Feature',
        properties: { 
          type: 'marker', 
          role: 'user-dropoff',
          name: userSearchedDropoff.name,
        },
        geometry: { type: 'Point', coordinates: [userSearchedDropoff.longitude, userSearchedDropoff.latitude] },
      });
    }

    // Safety: filter out any route features that have fewer than 2 coordinates
    const validRouteFeatures = routeFeatures.filter(
      f => f.geometry.coordinates && f.geometry.coordinates.length >= 2
    );

    return {
      geoJSON: {
        type: 'FeatureCollection',
        features: [...validRouteFeatures, ...stopMarkers],
      },
      bounds,
    };
  }, [routePath, stops, destination, currentUserLocation, sourceStopId, destinationStopId, userSearchedPickup, userSearchedDropoff, pickupRouteCoords, dropoffRouteCoords, initialStopIndex]);

  const [isMapLoaded, setIsMapLoaded] = useState(false);
  const handleMapLoaded = useCallback(() => setIsMapLoaded(true), []);

  const focusBounds = useMemo(() => {
    if (initialStopIndex !== undefined && stops && stops[initialStopIndex]) {
      const stop = stops[initialStopIndex];
      const stopCoord: [number, number] = [stop.lon, stop.lat];

      const isPickup = String(stop.id) === String(sourceStopId);
      const isDropoff = String(stop.id) === String(destinationStopId);

      if (isPickup && userSearchedPickup) {
        return getBoundingBox([
          stopCoord,
          [userSearchedPickup.longitude, userSearchedPickup.latitude],
        ]);
      } else if (isDropoff && userSearchedDropoff) {
        return getBoundingBox([
          stopCoord,
          [userSearchedDropoff.longitude, userSearchedDropoff.latitude],
        ]);
      }
    }
    return null;
  }, [initialStopIndex, stops, sourceStopId, destinationStopId, userSearchedPickup, userSearchedDropoff]);

  useEffect(() => {
    if (!isMapLoaded) return;
    const timer = setTimeout(() => {
      const controller = cameraRef.current || mapRef.current;
      if (focusBounds) {
        const [minLon, minLat, maxLon, maxLat] = focusBounds;
        cameraRef.current?.fitBounds(
          [minLon, minLat, maxLon, maxLat],
          { padding: { top: 120, right: 60, bottom: 280, left: 60 }, duration: 1000 }
        );
      } else if (initialStopIndex !== undefined || destination) {
        controller?.setStop({
          center: [initialPoint.lon, initialPoint.lat],
          zoom: 17,
          duration: 1000,
        });
      } else if (mapData.bounds) {
        const [minLon, minLat, maxLon, maxLat] = mapData.bounds;
        cameraRef.current?.fitBounds(
          [minLon, minLat, maxLon, maxLat],
          { padding: { top: 120, right: 60, bottom: 280, left: 60 }, duration: 1000 }
        );
      }
    }, 200);
    return () => clearTimeout(timer);
  }, [initialStopIndex, mapData.bounds, focusBounds, initialPoint, destination, isMapLoaded]);

  return {
    handleBack,
    handleUserLocationUpdate,
    handleRegionDidChange,
    handleZoomIn,
    handleZoomOut,
    handleOpenExternalMap,
    handleMapLoaded,
    mapData,
    currentUserLocation,
    cameraRef,
    mapRef,
    zoom,
    region,
    isMapMounted,
  };
};

import { useState, useCallback, useMemo } from 'react';
import { useBookRideStore } from '@/store/useBookRideStore';
import { FIVE_SEATER_ROWS, SEVEN_SEATER_ROWS } from '@/components/organisms/CarFloorPlan/seatConfig';
import rideService, { RouteStop } from '@/serviceManager/rideService';
import { useAppNavigation } from '@/hooks/useAppNavigation';
import { useTranslation } from '@/hooks/useTranslation';
import { showNotification } from '@/components/organisms/GlobalNotification/GlobalNotification';
import { NotificationType } from '@/constants/enums';
import { getErrorMessage } from '@/utils/error';

import { BookSeat, Passenger } from './types';

export const useBookSeatSelection = (
  rideId: string,
  sourceStopId?: number,
  destinationStopId?: number,
  passedSeats?: BookSeat[],
  passedPassengers?: Passenger[],
  passedVehicleType?: string,
  passedDate?: string,
  passedTime?: string
) => {
  const { navigate, goBack } = useAppNavigation();
  const { t: translate } = useTranslation();
  const searchResults = useBookRideStore(state => state.searchResults);
  const [selectedSeats, setSelectedSeats] = useState<Set<string | number>>(new Set());
  const [isBooking, setIsBooking] = useState(false);

  const rideRaw = useMemo(
    () => searchResults?.find((r: { id: string; vehicleType?: string; stops?: RouteStop[]; driverName?: string; vehicleRegistration?: string }) => r.id === rideId),
    [searchResults, rideId],
  );

  const vehicleType = useMemo(() => {
    const t = (passedVehicleType || rideRaw?.vehicleType || '').toUpperCase();
    return t.includes('7') ? '7' : '5';
  }, [passedVehicleType, rideRaw]);

  const occupiedSeats = useMemo(() => {
    const occupied = new Set<string>();
    const availableIds = new Set((passedSeats || []).map((s: BookSeat) => String(s.seatId)));

    // 1. Any standard seat ID that is not in the backend's returned seats list is unavailable/occupied
    const allIds = vehicleType === '7' ? [2, 3, 4, 5, 6, 7] : [2, 3, 4, 5];
    allIds.forEach(id => {
      if (!availableIds.has(String(id))) {
        occupied.add(String(id));
      }
    });

    // 2. Any seat in the backend returned seats list that is explicitly marked as not available is occupied
    (passedSeats || []).forEach((s: BookSeat) => {
      if (!s.available) {
        occupied.add(String(s.seatId));
      }
    });

    return occupied;
  }, [passedSeats, vehicleType]);

  const departureDate = useMemo(() => {
    if (passedDate) return passedDate;
    const firstStop = rideRaw?.stops?.[0];
    return firstStop?.arrivalTime
      ? new Date(firstStop.arrivalTime).toLocaleDateString('en-IN', {
        day: 'numeric',
        month: 'short',
      })
      : '-- ---';
  }, [rideRaw, passedDate]);

  const departureTime = useMemo(() => {
    if (passedTime) return passedTime;
    const firstStop = rideRaw?.stops?.[0];
    if (!firstStop?.arrivalTime) return '--:--';
    const date = new Date(firstStop.arrivalTime);
    return date.toLocaleTimeString('en-US', {
      hour: 'numeric',
      minute: '2-digit',
      hour12: true,
    });
  }, [rideRaw, passedTime]);

  const prices = useMemo(() => {
    const priceMap: Record<string | number, number> = {};
    (passedSeats || []).forEach((s: BookSeat) => {
      priceMap[s.seatId] = s.price;
    });
    return priceMap;
  }, [passedSeats]);

  const totalPrice: number = useMemo(() => {
    let total = 0;
    selectedSeats.forEach(id => {
      total += prices[id] || 0;
    });
    return total;
  }, [selectedSeats, prices]);

  const toggleSeat = useCallback((id: string | number) => {
    if (id === 'driver' || occupiedSeats.has(String(id))) return;
    setSelectedSeats(prev => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  }, [occupiedSeats]);

  const handleBack = useCallback(() => goBack(), [goBack]);

  const handleConfirm = useCallback(async () => {
    if (selectedSeats.size === 0 || isBooking) return;

    setIsBooking(true);
    try {
      const payload = {
        requestedSeatIds: Array.from(selectedSeats) as number[],
        sourceStopId: Number(sourceStopId),
        destinationStopId: Number(destinationStopId),
      };

      await rideService.bookRide(rideId, payload);
      navigate('BookingConfirmed', {
        rideId,
        bookedSeats: Array.from(selectedSeats).map(String),
        pickupTime: departureTime,
        vehicleType: passedVehicleType || rideRaw?.vehicleType || (vehicleType === '7' ? 'CAR_7_SEATER' : 'CAR_5_SEATER'),
        departureDate,
      });
    } catch (error: any) {
      console.error('Booking confirmation failed:', error);
      showNotification(
        NotificationType.ERROR,
        translate('notification.defaultErrorTitle'),
        getErrorMessage(error, translate('notification.defaultErrorMessage'))
      );
    } finally {
      setIsBooking(false);
    }
  }, [navigate, selectedSeats, rideId, isBooking, sourceStopId, destinationStopId]);

  return {
    rows: vehicleType === '7' ? SEVEN_SEATER_ROWS : FIVE_SEATER_ROWS,
    selectedSeats,
    occupiedSeats,
    prices,
    totalPrice,
    seatCount: selectedSeats.size,
    toggleSeat,
    handleBack,
    handleConfirm,
    driverName: rideRaw?.driverName ?? 'Host',
    vehicleRegistration: rideRaw?.vehicleRegistration ?? '',
    vehicleType,
    departureDate,
    departureTime,
    passengers: passedPassengers || [],
    isBooking,
  };
};

import { useCallback, useEffect, useMemo } from 'react';
import { useRoute, RouteProp, useFocusEffect } from '@react-navigation/native';
import { Share, BackHandler } from 'react-native';
import { useLocale } from '@/constants/localization';
import { RootStackParamList } from '@/navigation/types';
import { useBookRideStore } from '@/store/useBookRideStore';
import { useAppNavigation } from '@/hooks/useAppNavigation';
import { RouteStop } from '@/serviceManager/rideService';
import { formatTimeSafely } from '@/utils/date';

export const useBookingConfirmed = () => {
  const { navigate } = useAppNavigation();
  const navigation = useAppNavigation();

  useEffect(() => {
    navigation.setOptions({ headerLeft: () => null });
  }, [navigation]);
  const route = useRoute<RouteProp<RootStackParamList, 'BookingConfirmed'>>();
  const { bookingConfirmed: t } = useLocale();
  const searchResults = useBookRideStore(state => state.searchResults);

  // Prevent hardware back button on Android
  useFocusEffect(
    useCallback(() => {
      const onBackPress = () => {
        // Return true to stop default back behavior
        return true;
      };

      const subscription = BackHandler.addEventListener('hardwareBackPress', onBackPress);

      return () => subscription.remove();
    }, [])
  );

  const rideId = route.params?.rideId;
  const bookedSeats = route.params?.bookedSeats || [];

  const rideRaw = useMemo(
    () => searchResults?.find((r: { id: string; stops?: RouteStop[]; driverName?: string; driverPhotoUrl?: string; vehicleType?: string; vehicleRegistration?: string }) => r.id === rideId),
    [searchResults, rideId],
  );

  const rideData = useMemo(() => {
    const firstStop = rideRaw?.stops?.[0];
    const pickupTime = route.params?.pickupTime || formatTimeSafely(firstStop?.arrivalTime, {
      hour: 'numeric',
      minute: '2-digit',
      hour12: true,
    });

    const vehicleType = route.params?.vehicleType || rideRaw?.vehicleType;
    const departureDate = route.params?.departureDate || (firstStop?.arrivalTime
      ? new Date(firstStop.arrivalTime).toLocaleDateString('en-IN', {
        day: 'numeric',
        month: 'short',
      })
      : '');

    const getSeatDescription = (seatId: string | number, vType?: string): string => {
      const id = String(seatId);
      const typeStr = (vType || '').toUpperCase();
      const is7Seater = typeStr.includes('7') || typeStr === '7';

      if (id === '1' || id === 'driver') return t.seatPositions.driver;
      if (id === '2') return t.seatPositions.frontPassenger;

      if (is7Seater) {
        switch (id) {
          case '3': return t.seatPositions.middleLeft;
          case '4': return t.seatPositions.middleCenter;
          case '5': return t.seatPositions.middleRight;
          case '6': return t.seatPositions.backLeft;
          case '7': return t.seatPositions.backRight;
        }
      } else {
        // 5 Seater or default
        switch (id) {
          case '3': return t.seatPositions.backLeft;
          case '4': return t.seatPositions.backCenter;
          case '5': return t.seatPositions.backRight;
        }
      }

      return t.seatPositions.defaultSeat.replace('{id}', id);
    };

    const formattedSeats = bookedSeats.length > 0 
      ? bookedSeats.map(seatId => getSeatDescription(seatId, vehicleType)).join(', ')
      : 'TBD';

    return {
      driver: {
        name: rideRaw?.driverName || 'Host',
        rating: 4.9,
        avatar: rideRaw?.driverPhotoUrl || 'https://ui-avatars.com/api/?name=' + (rideRaw?.driverName || 'H'),
        isVerified: true,
        car: vehicleType?.replace('CAR_', '').replace('_', '-').toLowerCase().replace(/\b\w/g, (c: string) => c.toUpperCase()) || 'Vehicle',
        plate: rideRaw?.vehicleRegistration || '...',
      },
      pickupTime,
      arrivalInMins: 12, // Still mock or calculate if possible
      seatNumber: formattedSeats,
      seatPreference: t.windowPreference,
      departureDate,
    };
  }, [rideRaw, bookedSeats, route.params, t]);

  const handleGoToMyRides = useCallback(() => {
    navigate('MyRides');
  }, [navigate]);

  const handleShareDetails = useCallback(async () => {
    try {
      await Share.share({
        message: `My ride with ${rideData.driver.name} is confirmed for ${rideData.pickupTime}. Plate: ${rideData.driver.plate}`,
      });
    } catch (error) {
      console.error('Error sharing details:', error);
    }
  }, [rideData]);

  const handleMenuPress = useCallback(() => {
    // Placeholder for menu toggle
  }, []);

  return {
    t,
    rideData,
    handleGoToMyRides,
    handleShareDetails,
    handleMenuPress,
  };
};

