const SCREEN_WIDTH = Dimensions.get('window').width;

export const MyRidesScreen: React.FC = memo(() => {
  const { t } = useTranslation();
  const theme = useTheme();
  const {
    activeTab,
    onTabChange,
    onAcceptRide,
    onRejectRide,
    onRidePress,
    onChatPress,
    onRemoveDraft,
    onCancelRide,
    onClearDrafts,
    onRefresh,
    onLoadMore,
    isRefreshing,
    isLoading,
    isActionLoading,
    getTabData,
    drafts,
    hasRequests,
    mappedRequests,
    confirmModalConfig,
    hideConfirmModal,
  } = useMyRides();

  const flatListRef = useRef<FlatList>(null);

  const TABS = useMemo(() => {
    const all = ['requests', 'upcoming', 'drafts', 'archive'] as const;
    return all.filter(tab => tab !== 'requests' || hasRequests);
  }, [hasRequests]);

  // Sync tab clicks to horizontal scroll
  useEffect(() => {
    const index = TABS.indexOf(activeTab as any);
    if (index >= 0 && flatListRef.current) {
      flatListRef.current.scrollToIndex({ index, animated: true });
    }
  }, [activeTab, TABS]);

  const onMomentumScrollEnd = useCallback((e: any) => {
    const index = Math.round(e.nativeEvent.contentOffset.x / SCREEN_WIDTH);
    const newTab = TABS[index];
    if (newTab && newTab !== activeTab) {
      onTabChange(newTab);
    }
  }, [TABS, activeTab, onTabChange]);

  const renderItem = useCallback(({ item, activeTab: tab }: { item: any, activeTab: string }) => (
    <RideItem 
      item={item}
      activeTab={tab as any}
      onRidePress={onRidePress}
      onChatPress={onChatPress}
      onCancelRide={onCancelRide}
      onRemoveDraft={onRemoveDraft}
      onAcceptRide={onAcceptRide}
      onRejectRide={onRejectRide}
      isActionLoading={isActionLoading}
    />
  ), [onRidePress, onChatPress, onCancelRide, onRemoveDraft, onAcceptRide, onRejectRide, isActionLoading]);

  const renderTabContent = useCallback(({ item: tab }: { item: typeof TABS[number] }) => {
    const data = getTabData(tab);

    const iconMap: Record<string, string> = {
      upcoming: "event-note",
      requests: "person-add",
      drafts: "edit-note",
      archive: "inventory"
    };

    const emptyComponent = (
      <EmptyState 
        icon={iconMap[tab] || "inventory"}
        title={t(`myRides.no${tab.charAt(0).toUpperCase() + tab.slice(1)}Title`)}
        description={t(`myRides.no${tab.charAt(0).toUpperCase() + tab.slice(1)}Desc`)}
      />
    );

    const listHeader = (
      <RideListHeader 
        activeTab={tab}
        draftsCount={drafts?.length || 0}
        onClearDrafts={onClearDrafts}
        requests={mappedRequests}
      />
    );

    const footerComponent = isLoading && !isRefreshing && tab === activeTab ? (
      <Box paddingVertical={verticalScale(20)} alignItems="center">
        <ActivityIndicator color={theme.colors.primary} />
      </Box>
    ) : null;

    return (
      <Box style={{ width: SCREEN_WIDTH, flex: 1 }}>
        <FlashList
          data={data}
          renderItem={({ item }) => renderItem({ item, activeTab: tab })}
          keyExtractor={(item) => item.id}
          showsVerticalScrollIndicator={false}
          contentContainerStyle={{
            paddingHorizontal: scale(24),
            paddingBottom: verticalScale(120),
          }}
          ListHeaderComponent={listHeader}
          ListEmptyComponent={emptyComponent}
          ListFooterComponent={footerComponent}
          onEndReached={tab === activeTab ? onLoadMore : undefined}
          onEndReachedThreshold={0.5}
          refreshControl={
            <RefreshControl
              refreshing={isRefreshing && tab === activeTab}
              onRefresh={onRefresh}
              tintColor={theme.colors.primary}
              colors={[theme.colors.primary]}
            />
          }
        />
      </Box>
    );
  }, [getTabData, drafts?.length, mappedRequests, isLoading, isRefreshing, activeTab, theme.colors.primary, t, onClearDrafts, renderItem, onLoadMore, onRefresh]);

  return (
    <>
      <MyRidesTemplate 
        header={
          <MyRidesHeader 
            activeTab={activeTab} 
            onTabChange={onTabChange} 
            onMenuPress={() => {}} 
            onProfilePress={() => {}} 
            userAvatarUri={USER_AVATAR}
            hasRequests={hasRequests}
          />
        }
        bottomNav={<BottomNav activeTab="MY_RIDES" />}
      >
        <FlatList
          ref={flatListRef}
          style={{ flex: 1 }}
          horizontal
          pagingEnabled
          showsHorizontalScrollIndicator={false}
          data={TABS}
          keyExtractor={item => item}
          renderItem={renderTabContent}
          onMomentumScrollEnd={onMomentumScrollEnd}
          initialNumToRender={1}
          maxToRenderPerBatch={2}
          windowSize={3}
          getItemLayout={(data, index) => (
            { length: SCREEN_WIDTH, offset: SCREEN_WIDTH * index, index }
          )}
        />
      </MyRidesTemplate>
      <Loader visible={isActionLoading} />
      {confirmModalConfig.isVisible && (
        <ConfirmationModal
          isVisible={confirmModalConfig.isVisible}
          onClose={hideConfirmModal}
          onConfirm={confirmModalConfig.onConfirm}
          title={confirmModalConfig.title}
          message={confirmModalConfig.message}
          confirmLabel={confirmModalConfig.confirmLabel}
          cancelLabel={confirmModalConfig.cancelLabel}
          type={confirmModalConfig.type}
        />
      )}
    </>
  );
});

import { useState, useCallback, useMemo, useEffect } from 'react';
import { useRoute } from '@react-navigation/native';
import { MyRidesTab } from '@/components/organisms/MyRidesHeader/types.d';
import { useMyRidesData, TAB_TO_FILTER } from './useMyRidesData';
import { useMyRidesActions } from './useMyRidesActions';
import { mapBackendRideToUI } from './utils/rideMapper';
import { MyRidesHookData, RideListItem } from './types.d';
import { useTranslation } from '@/hooks/useTranslation';
import rideService from '@/serviceManager/rideService';
import { showNotification } from '@/components/organisms/GlobalNotification/GlobalNotification';
import { NotificationType } from '@/constants/enums';
import { getErrorMessage } from '@/utils/error';

export const useMyRides = (): MyRidesHookData => {
  const { t } = useTranslation();
  const route = useRoute<any>();
  const initialTab = route.params?.tab || 'upcoming';
  const [activeTab, setActiveTab] = useState<MyRidesTab>(initialTab);

  useEffect(() => {
    if (route.params?.tab) {
      setActiveTab(route.params.tab);
    }
  }, [route.params?.tab]);

  const [isActionLoading, setIsActionLoading] = useState(false);

  const {
    isLoading,
    isRefreshing,
    onRefresh,
    onLoadMore,
    rides,
    fetchInitialRides
  } = useMyRidesData(activeTab);

  // Auto-switch to requests tab if data exists on first load
  useState(() => {
    if (rides?.[3]?.data?.length > 0) {
      setActiveTab('requests');
    }
  });

  const [confirmModalConfig, setConfirmModalConfig] = useState<{
    isVisible: boolean;
    title: string;
    message: string;
    confirmLabel?: string;
    cancelLabel?: string;
    onConfirm: () => void;
    type?: 'info' | 'danger' | 'warning';
  }>({
    isVisible: false,
    title: '',
    message: '',
    onConfirm: () => {},
  });

  const showConfirm = useCallback((config: any) => {
    setConfirmModalConfig({
      isVisible: true,
      title: config.title,
      message: config.message,
      confirmLabel: config.confirmLabel,
      cancelLabel: config.cancelLabel,
      onConfirm: () => {
        config.onConfirm();
        setConfirmModalConfig(prev => ({ ...prev, isVisible: false }));
      },
      type: config.type,
    });
  }, []);

  const hideConfirmModal = useCallback(() => {
    setConfirmModalConfig(prev => ({ ...prev, isVisible: false }));
  }, []);

  const {
    onRidePress,
    onRemoveDraft,
    onCancelRide,
    onClearDrafts,
    onChatPress,
    drafts
  } = useMyRidesActions(fetchInitialRides, showConfirm);

  const onTabChange = useCallback((tab: MyRidesTab) => {
    setActiveTab(tab);
  }, []);

  const mappedRequests = useMemo(() => 
    (rides?.[3]?.data || []).map(r => mapBackendRideToUI(r, 'requests' as any, t)), 
  [rides?.[3]?.data, t]);

  const hasRequests = mappedRequests.length > 0;

  // If on requests tab and requests disappear, switch to upcoming
  useEffect(() => {
    if (activeTab === 'requests' && !hasRequests) {
      setActiveTab('upcoming');
    }
  }, [activeTab, hasRequests]);

  const formattedDrafts = useMemo((): RideListItem[] => {
    return drafts.map((draft) => {
      const start = draft.state.startLocation?.name || 'Unknown';
      const end = draft.state.destinationLocation?.name || 'Unknown';
      const dateStr = draft.state.departureDate 
        ? new Date(draft.state.departureDate).toLocaleDateString() 
        : 'No date';
      return {
        id: draft.id,
        title: `${start} to ${end}`,
        subtitle: `Draft • ${dateStr}`,
        price: draft.state.fullJourneyPrice ? `₹${draft.state.fullJourneyPrice}` : (draft.state.price ? `₹${draft.state.price}` : '₹0'),
        type: 'draft' as const,
      };
    });
  }, [drafts]);

  const mappedUpcoming = useMemo(() => 
    (rides?.[1]?.data || []).map(r => mapBackendRideToUI(r, 'upcoming', t)), 
  [rides?.[1]?.data, t]);

  const mappedArchive = useMemo(() => 
    (rides?.[2]?.data || []).map(r => mapBackendRideToUI(r, 'archive', t)), 
  [rides?.[2]?.data, t]);

  const getTabData = useCallback((tab: MyRidesTab) => {
    if (tab === 'drafts') return formattedDrafts;
    if (tab === 'requests') return mappedRequests;

    const allRides = tab === 'upcoming' ? mappedUpcoming : mappedArchive;

    return [...allRides].sort((a, b) => {
      const timeA = a.rawDate?.getTime() || 0;
      const timeB = b.rawDate?.getTime() || 0;
      return tab === 'upcoming' ? timeA - timeB : timeB - timeA;
    });
  }, [mappedUpcoming, mappedArchive, mappedRequests, formattedDrafts]);

  const onAcceptBooking = useCallback(async (id: string) => {
    setIsActionLoading(true);
    try {
      await rideService.acceptBooking(id);
      showNotification(
        NotificationType.SUCCESS,
        t('notification.defaultSuccessTitle'),
        t('notification.bookingAccepted')
      );
      onRefresh();
    } catch (error: any) {
      console.error('Failed to accept booking:', error);
      showNotification(
        NotificationType.ERROR,
        t('notification.defaultErrorTitle'),
        getErrorMessage(error, t('notification.defaultErrorMessage'))
      );
    } finally {
      setIsActionLoading(false);
    }
  }, [onRefresh, t]);

  const onRejectBooking = useCallback(async (id: string) => {
    setIsActionLoading(true);
    try {
      await rideService.rejectBooking(id);
      showNotification(
        NotificationType.SUCCESS,
        t('notification.defaultSuccessTitle'),
        t('notification.bookingRejected')
      );
      onRefresh();
    } catch (error: any) {
      console.error('Failed to reject booking:', error);
      showNotification(
        NotificationType.ERROR,
        t('notification.defaultErrorTitle'),
        getErrorMessage(error, t('notification.defaultErrorMessage'))
      );
    } finally {
      setIsActionLoading(false);
    }
  }, [onRefresh, t]);

  return {
    activeTab,
    isLoading,
    isRefreshing,
    isActionLoading,
    onTabChange,
    onRidePress,
    onRemoveDraft,
    onCancelRide,
    onClearDrafts,
    onChatPress,
    onRefresh,
    onLoadMore,
    hasMore: TAB_TO_FILTER[activeTab] ? rides?.[TAB_TO_FILTER[activeTab]!]?.hasMore : false,
    getTabData,
    drafts,
    mappedRequests,
    hasRequests,
    onMenuPress: () => {},
    onProfilePress: () => {},
    onAcceptRide: onAcceptBooking,
    onRejectRide: onRejectBooking,
    confirmModalConfig,
    hideConfirmModal,
  };
};

import { useState, useCallback, useEffect } from 'react';
import { useIsFocused } from '@react-navigation/native';
import { useMyRidesStore, RideCategory } from '@/store/useMyRidesStore';
import rideService from '@/serviceManager/rideService';
import { useAuthStore } from '@/store/useAuthStore';
import { MyRidesTab } from '@/components/organisms/MyRidesHeader/types.d';
import { Logger } from '@/utils/logger';
import { useTranslation } from '@/hooks/useTranslation';
import { showNotification } from '@/components/organisms/GlobalNotification/GlobalNotification';
import { NotificationType } from '@/constants/enums';
import { getErrorMessage } from '@/utils/error';

export const TAB_TO_FILTER: Record<string, RideCategory | null> = {
  upcoming: 1,
  archive: 2,
  requests: 3,
  drafts: null,
};

export const useMyRidesData = (activeTab: MyRidesTab) => {
  const isFocused = useIsFocused();
  const [isLoading, setIsLoading] = useState(false);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const { t } = useTranslation();

  const { rides, setRides, appendRides, setPage } = useMyRidesStore();
  const { user } = useAuthStore();

  const parseRideResponse = (response: any): any[] => {
    if (Array.isArray(response)) return response;
    if (response?.rides && Array.isArray(response.rides)) return response.rides;
    if (response?.data && Array.isArray(response.data)) return response.data;
    if (response?.content && Array.isArray(response.content)) return response.content;
    if (response?.requests && Array.isArray(response.requests)) return response.requests;
    return [];
  };

  const fetchCategoryRides = useCallback(async (category: RideCategory, page: number = 0, append: boolean = false) => {
    // Caching check: if not refreshing and we already have data for this page (and it's full), skip
    const { rides: currentRides } = useMyRidesStore.getState();
    const currentCategoryData = currentRides[category];
    if (!isRefreshing && append && currentCategoryData?.data?.length >= (page + 1) * 10) {
      Logger.log(`[MyRidesData] Using cached data for ${category} page ${page}`);
      return;
    }

    if (page === 0 && !isRefreshing) setIsLoading(true);

    try {
      let rideList: any[] = [];
      let hasMore = false;

      let response: any;
      if (category === 3) {
        response = await rideService.getDriverPendingRequests();
      } else {
        response = await rideService.getMyRides(category, page, 10);
      }

      rideList = parseRideResponse(response);

      if (category === 3) {
        hasMore = false; // Assuming driver pending requests API doesn't paginate
      } else if (response?.totalPages !== undefined && response?.currentPage !== undefined) {
        hasMore = response.currentPage < response.totalPages - 1;
      } else {
        hasMore = rideList.length >= 10;
      }

      // Special sort for archive (filter 2)
      if (category === 2) {
        rideList = rideList.sort((a, b) => {
          const dateA = new Date(a.startTime || a.createdAt || 0).getTime();
          const dateB = new Date(b.startTime || b.createdAt || 0).getTime();
          return dateB - dateA;
        });
      }

      if (append) {
        appendRides(category, rideList, hasMore);
      } else {
        setRides(category, rideList, hasMore);
      }
    } catch (error) {
      Logger.error(`[MyRidesData] Failed to fetch ${category} rides:`, error);
      showNotification(
        NotificationType.ERROR,
        t('notification.defaultErrorTitle'),
        getErrorMessage(error, t('notification.defaultErrorMessage'))
      );
    } finally {
      setIsLoading(false);
      setIsRefreshing(false);
    }
  }, [setRides, appendRides, isRefreshing]);

  const fetchInitialRides = useCallback(() => {
    const filter = TAB_TO_FILTER[activeTab];

    // Always fetch requests to know if we should show the tab
    fetchCategoryRides(3, 0, false);

    if (filter !== null && filter !== undefined && filter !== 3) {
      fetchCategoryRides(filter, 0, false);
    }
  }, [activeTab, fetchCategoryRides]);

  useEffect(() => {
    if (isFocused) {
      fetchInitialRides();
    }
  }, [isFocused, fetchInitialRides]);

  const onRefresh = useCallback(() => {
    setIsRefreshing(true);
    fetchInitialRides();
  }, [fetchInitialRides]);

  const onLoadMore = useCallback(() => {
    const filter = TAB_TO_FILTER[activeTab];
    const { rides: currentRides } = useMyRidesStore.getState();
    const categoryState = filter ? currentRides?.[filter] : null;

    if (filter && categoryState?.hasMore && !isLoading) {
      const nextPage = (categoryState?.page || 0) + 1;
      setPage(filter, nextPage);
      fetchCategoryRides(filter, nextPage, true);
    }
  }, [activeTab, isLoading, fetchCategoryRides, setPage]);

  return {
    isLoading,
    isRefreshing,
    onRefresh,
    onLoadMore,
    rides,
    fetchInitialRides
  };
};

import { RideCategory } from '@/store/useMyRidesStore';
import { safeParseDate, formatTimeSafely, formatDateSafely } from '@/utils/date';

export const mapBackendRideToUI = (ride: any, type: 'upcoming' | 'completed' | 'requests' | 'archive', t: any) => {
  const startName = ride.sourceStopName || 'Unknown';
  const endName = ride.destinationStopName || 'Unknown';
  const startTime = safeParseDate(ride.startTime || ride.requestedAt) || new Date();

  const now = new Date();
  const diffMs = startTime.getTime() - now.getTime();
  const diffMins = Math.floor(diffMs / 60000);
  const diffHours = Math.floor(diffMins / 60);
  const isDriver = ride.role === 'DRIVER';
  const isPassenger = ride.role === 'PASSENGER';
  const isRequest = type === 'requests';

  let weekday = 'Today';
  let dayMonth = '';
  try {
    weekday = startTime.toLocaleDateString('en-US', { weekday: 'short' });
    dayMonth = startTime.toLocaleDateString('en-US', { day: 'numeric', month: 'short' });
  } catch (e) { }
  const timeStr = formatTimeSafely(ride.startTime || ride.requestedAt);

  let timerLabel = '';
  let statusTag = '';

  if (type === 'upcoming') {
    if (isDriver) {
      statusTag = (ride.status === 'SCHEDULED' || ride.status === 'CONFIRMED') ? t('myRides.confirmedStatus') : '';
    } else {
      statusTag = ride.status === 'PENDING' ? t('myRides.pendingStatus') : ((ride.status === 'SCHEDULED' || ride.status === 'CONFIRMED') ? t('myRides.confirmedStatus') : '');
    }

    if (diffMins < 0) {
      timerLabel = t('myRides.started');
    } else if (diffMins < 60) {
      timerLabel = `${t('myRides.startsIn')} ${diffMins}${t('myRides.mins')}`;
    } else if (diffHours < 24) {
      timerLabel = `${t('myRides.startsIn')} ${diffHours}${t('myRides.hours')} ${diffMins % 60}${t('myRides.mins')}`;
    } else {
      timerLabel = `${weekday}, ${dayMonth}`;
    }
  } else if (type === 'requests') {
    timerLabel = `Requested ${timeStr}`;
    statusTag = `${ride.seatCount || 1} Seat${(ride.seatCount || 1) > 1 ? 's' : ''}`;
  } else if (type === 'archive') {
    statusTag = ride.status === 'CANCELLED' ? t('common.cancelled') : t('myRides.completedStatus');
    timerLabel = statusTag;
  } else {
    timerLabel = t('myRides.completedStatus');
  }

  return {
    id: ride.bookingId || ride.id || ride._id || Math.random().toString(),
    rideId: ride.rideId || ride.id,
    bookingId: ride.bookingId,
    title: `${startName.split(',')[0]} to ${endName.split(',')[0]}`,
    subtitle: isRequest ? `${weekday}, ${dayMonth} • ${timeStr}` : `${weekday}, ${dayMonth} • ${timeStr}`,
    price: `₹${ride.price || ride.totalPrice || 0}`,
    icon: type === 'completed' ? 'check-circle' : (type === 'requests' ? 'person-add' : (isDriver ? 'navigation' : 'directions-car')),
    type,
    driverName: isRequest
      ? (ride.passengerName)
      : (isDriver ? undefined : (ride.name)),
    carModel: isRequest
      ? `Requested by ${ride.passengerName}`
      : (ride.vehicleRegistration
        ? `${ride.vehicleType?.replace('_', ' ') || 'CAR'} (${ride.vehicleRegistration})`
        : (isDriver ? t('myRides.yourVehicle') : t('myRides.vehicleDetails'))),
    rating: (ride.rating || 0),
    avatarUri: isRequest 
      ? (ride.passengerPhotoUrl)
      : (isDriver ? undefined : ride.photoUrl),
    pickupTime: timeStr,
    dropoffTime: formatTimeSafely(
      ride.endTime,
      { hour: '2-digit', minute: '2-digit' },
      formatTimeSafely(new Date(startTime.getTime() + 3600000))
    ),
    pickupLocation: isRequest ? startName : startName.split(',')[0],
    dropoffLocation: isRequest ? endName : endName.split(',')[0],
    timerLabel,
    statusTag,
    rawDate: startTime,
    role: ride.role,
    status: ride.status,
  };
};

import React, { memo } from 'react';
import { MyRideDetailsTemplate } from '@/components/templates/MyRideDetailsTemplate';
import { ScreenShell } from '@/components/molecules/ScreenShell';
import { Loader } from '@/components/atoms/Loader';
import { useRideDetails } from './useRideDetails';
import { RideDetailsScreenProps } from './types';
import { CancelRideModal } from '@/components/organisms/CancelRideModal';
import { Container, Overlay } from './RideDetails.styles';
import { Box } from '@/components/atoms/Box';
import { ReportIssueModal } from '@/components/organisms/ReportIssueModal';

export const RideDetailsScreen: React.FC<RideDetailsScreenProps> = memo(() => {
  const { 
    ride, 
    isLoading, 
    isDriver,
    t, 
    handleBack, 
    handleViewRoute, 
    handleCopyAddress,
    handleChat,
    handleDriverProfile,
    handlePassengerProfile,
    handleCancelRide,
    handleCancelPassenger,
    handleCancelOwnBooking,
    isCancelModalVisible,
    setIsCancelModalVisible,
    cancellationReasons,
    handleConfirmCancel,
    isCancelling,
    cancelTarget,
    handleReportRide,
    isReportModalVisible,
    setIsReportModalVisible,
    handleReportSubmit,
  } = useRideDetails();

  if (isLoading) {
    return (
      <ScreenShell title={t.title} onBack={handleBack}>
        <Loader message={t.loaderMessage} />
      </ScreenShell>
    );
  }

  if (!ride) return null;

  return (
    <Container>
      <MyRideDetailsTemplate
        t={t}
        handleBack={handleBack}
        ride={ride}
        handleViewRoute={handleViewRoute}
        handleCopyAddress={handleCopyAddress}
        handleChat={handleChat}
        handleDriverProfile={handleDriverProfile}
        handlePassengerProfile={handlePassengerProfile}
        isDriver={isDriver}
        onCancelRide={handleCancelRide}
        onCancelPassenger={(id) => (isDriver ? handleCancelPassenger(id) : handleCancelOwnBooking())}
        onReportRide={handleReportRide}
      />

      {isCancelModalVisible && (
        <CancelRideModal
          isVisible={isCancelModalVisible}
          onClose={() => setIsCancelModalVisible(false)}
          onSubmit={handleConfirmCancel}
          bookingId={cancelTarget?.id?.toString() || ride.myBookingId || ride.id || 'Ride'}
          isDriver={isDriver}
          isSpecificUser={cancelTarget?.type === 'BOOKING' && !cancelTarget?.isSelf}
          isLoading={isCancelling}
        />
      )}

      {isReportModalVisible && (
        <ReportIssueModal
          isVisible={isReportModalVisible}
          onClose={() => setIsReportModalVisible(false)}
          onSubmit={handleReportSubmit}
          bookingId={ride.myBookingId || ride.id || 'Ride'}
        />
      )}
    </Container>
  );
});

import { useAppNavigation } from '@/hooks/useAppNavigation';
import { useCallback, useEffect, useState, useMemo } from 'react';
import { Alert, Clipboard } from 'react-native';
import { useRoute } from '@react-navigation/native';
import { useTranslation } from '@/hooks/useTranslation';
import { useAuthStore } from '@/store/useAuthStore';
import { RideDetailsScreenProps } from './types';
import rideService from '@/serviceManager/rideService';
import { useMyRidesStore } from '@/store/useMyRidesStore';
import { Logger } from '@/utils/logger';
import { showNotification } from '@/components/organisms/GlobalNotification/GlobalNotification';
import { NotificationType } from '@/constants/enums';
import { getErrorMessage } from '@/utils/error';
import { useBookRideStore } from '@/store/useBookRideStore';
import { navigate } from '@/navigation/navigationService';

export const useRideDetails = () => {
  const navigation = useAppNavigation();
  const route = useRoute<RideDetailsScreenProps['route']>();
  const { rideId, sourceStopId, destinationStopId } = route.params;
  const { t } = useTranslation();
  const { user } = useAuthStore();

  const [isLoading, setIsLoading] = useState(true);
  const [rideData, setRideData] = useState<any>(null);

  const fetchDetails = useCallback(async () => {
    setIsLoading(true);
    try {
      const data = await rideService.getMyRideDetail(rideId, sourceStopId, destinationStopId);

      // Merge route parameters if fields are missing in raw response
      if (data) {
        if (!data.status && route.params.status) {
          data.status = route.params.status;
        }
        if (!data.cancellationReason && route.params.cancellationReason) {
          data.cancellationReason = route.params.cancellationReason;
        }
      }

      setRideData(data);
    } catch (error) {
      Logger.error('Fetching ride details failed:', error);
      showNotification(
        NotificationType.ERROR,
        t('notification.defaultErrorTitle'),
        getErrorMessage(error, t('notification.defaultErrorMessage'))
      );
    } finally {
      setIsLoading(false);
    }
  }, [rideId, sourceStopId, destinationStopId, route.params]);

  useEffect(() => {
    fetchDetails();
  }, [fetchDetails]);

  const handleBack = useCallback(() => {
    navigation.goBack();
  }, [navigation]);

  const handleBook = useCallback(() => {
    // Placeholder for future booking logic if needed
  }, []);

  const isDriver = useMemo(() => {
    return rideData?.role === 'DRIVER';
  }, [rideData]);

  const [isCancelModalVisible, setIsCancelModalVisible] = useState(false);
  const [cancelTarget, setCancelTarget] = useState<{ type: 'RIDE' | 'BOOKING'; id: string | number; isSelf?: boolean } | null>(null);
  const [isCancelling, setIsCancelling] = useState(false);

  const [isReportModalVisible, setIsReportModalVisible] = useState(false);

  const handleReportRide = useCallback(() => {
    setIsReportModalVisible(true);
  }, []);

  const handleReportSubmit = useCallback((_data: { categoryId: string; description: string }) => {
    setIsReportModalVisible(false);
    showNotification(
      NotificationType.SUCCESS,
      t('rideDetails.reportSuccessTitle'),
      t('rideDetails.reportSuccessMessage')
    );
  }, [t]);

  const cancellationReasons = useMemo(() => [
    { id: 'change_plans', label: t('cancelRide.reasonPlansChanged') },
    { id: 'found_alternative', label: t('cancelRide.reasonAlternative') },
    { id: 'uncomfortable_pickup', label: t('cancelRide.reasonUncomfortable') },
    { id: 'not_available', label: t('cancelRide.reasonNotAvailable') },
    { id: 'other', label: t('cancelRide.reasonOther') },
  ], [t]);

  const handleOpenCancelModal = useCallback((type: 'RIDE' | 'BOOKING', id: string | number, isSelf: boolean = false) => {
    setCancelTarget({ type, id, isSelf });
    setIsCancelModalVisible(true);
  }, []);

  const handleConfirmCancel = useCallback(async ({ categoryId, description }: { categoryId: string; description: string }) => {
    if (!cancelTarget) return;

    const reason = description ? `${categoryId}: ${description}` : categoryId;

    const bookingId = cancelTarget.id || rideData?.myBooking?.bookingId || rideId;
    setIsCancelling(true);
    try {
      if (cancelTarget.type === 'RIDE') {
        await rideService.cancelRide(bookingId, reason);
        const { removeRide } = useMyRidesStore.getState();
        removeRide(1, rideId);
        navigation.goBack();
      } else {
        await rideService.cancelBooking(bookingId, reason);
        if (cancelTarget.isSelf) {
          const { removeRide } = useMyRidesStore.getState();
          removeRide(1, bookingId);
          navigation.goBack();
        } else {
          fetchDetails();
        }
      }
      setIsCancelModalVisible(false);
      showNotification(
        NotificationType.SUCCESS,
        t('common.success'),
        t('cancelRide.successMessage')
      );
    } catch (error) {
      showNotification(
        NotificationType.ERROR,
        t('common.error'),
        getErrorMessage(error, t('cancelRide.errorMessage'))
      );
    } finally {
      setIsCancelling(false);
    }
  }, [cancelTarget, rideData, fetchDetails, navigation, rideId, t]);

  const handleCancelRide = useCallback(() => {
    handleOpenCancelModal('RIDE', rideId, true);
  }, [rideId, handleOpenCancelModal]);

  const handleCancelPassenger = useCallback((bookingId: string) => {
    handleOpenCancelModal('BOOKING', bookingId, false);
  }, [handleOpenCancelModal]);

  const handleCancelOwnBooking = useCallback(() => {
    handleOpenCancelModal('BOOKING', rideData?.myBooking?.bookingId || 0, true);
  }, [rideData, handleOpenCancelModal]);

  const handleDriverProfile = useCallback(() => {
    if (rideData?.driver?.id) {
      navigate('UserProfileDetail', { userId: rideData.driver.id });
    }
  }, [navigate, rideData]);

  const handlePassengerProfile = useCallback((id: string) => {
    navigate('UserProfileDetail', { userId: id });
  }, [navigate]);

  const handleChat = useCallback(() => {
    const targetName = isDriver ? t('rideDetails.passengers') : (rideData?.driver?.name || t('rideDetails.driver'));
    const startLoc = rideData?.stops?.[0]?.stopName?.split(',')[0] || '';
    const endLoc = rideData?.stops?.[rideData?.stops.length - 1]?.stopName?.split(',')[0] || '';
    const startTimeStr = rideData?.startTime 
      ? new Date(rideData.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      : '';
    const dateStr = rideData?.startTime
      ? new Date(rideData.startTime).toLocaleDateString()
      : '';

    (navigation.navigate as any)('ChatDetails', { 
      userId: isDriver 
        ? (rideData?.passengers?.[0]?.passengerId) 
        : (rideData?.driver?.driverId || rideData?.driver?.userId),
      rideId: rideId,
      name: targetName,
      avatarUri: isDriver ? undefined : rideData?.driver?.photoUrl,
      rideInfo: {
        pickup: startLoc,
        dropoff: endLoc,
        date: dateStr,
