import { useAppNavigation } from '@/hooks/useAppNavigation';
import { useCallback, useEffect, useState } from 'react';
import { Keyboard } from 'react-native';
import { StackNavigationProp } from '@react-navigation/stack';
import { RootStackParamList } from '@/navigation/types';
import { useRidePublishStore } from '@/store/useRidePublishStore';
import { storage } from '@/utils/storage';

type NavigationProp = StackNavigationProp<RootStackParamList, 'LocationSelection'>;

export const useLocationSelection = () => {
  const navigation = useAppNavigation();

  const { 
    startLocation, 
    destinationLocation, 
    clearPublishState
  } = useRidePublishStore();

  const [recentRides, setRecentRides] = useState<any[]>([]);

  // Clear state when the publish flow is completely exited
  useEffect(() => {
    return () => {
      clearPublishState();
    };
  }, [clearPublishState]);

  // Load recent published rides from MMKV
  useEffect(() => {
    try {
      const raw = storage.getString('recent_published_rides');
      if (raw) {
        setRecentRides(JSON.parse(raw));
      }
    } catch (err) {
      console.error('[MMKV] Failed to load recent rides:', err);
    }
  }, []);

  const handlePressStart = useCallback(() => {
    Keyboard.dismiss();
    navigation.push('MapPicker', { 
      type: 'start', 
      returnTo: 'LocationSelection',
      module: 'publish'
    });
  }, [navigation]);

  const handlePressDestination = useCallback(() => {
    Keyboard.dismiss();
    navigation.push('MapPicker', { 
      type: 'destination', 
      returnTo: 'LocationSelection',
      module: 'publish'
    });
  }, [navigation]);


  const handleContinue = useCallback(() => {
    Keyboard.dismiss();
    navigation.navigate('RouteSelection');
  }, [navigation]);

  const handleSelectRecentRide = useCallback((ride: any) => {
    Keyboard.dismiss();
    useRidePublishStore.setState({
      startLocation: ride.startLocation,
      destinationLocation: ride.destinationLocation,
      middleStops: ride.middleStops || [],
      routeDetails: ride.routeDetails,
      selectedRoute: ride.selectedRoute,
      seatCount: ride.seatCount || 1,
      selectedSeatIds: ride.selectedSeatIds || [],
      vehicleId: ride.vehicleId,
      publishVehicleType: ride.publishVehicleType || '5',
      vehicleDetails: ride.vehicleDetails,
      preferences: ride.preferences,
      price: ride.price || 0,
      fullJourneyPrice: ride.fullJourneyPrice || 0,
      frontSeatPrice: ride.frontSeatPrice || 0,
      premiumEnabled: ride.premiumEnabled !== undefined ? ride.premiumEnabled : true,
      premiumPercentage: ride.premiumPercentage || 10,
      segmentPrices: ride.segmentPrices || {},
      requestType: ride.requestType || 'instant',
      departureDate: null,
      departureTime: null,
    });

    (navigation.navigate as any)('DateSelection', {
      returnTo: 'SummaryPublish',
    });
  }, [navigation]);

  // Enforce validation: Must have both start and destination to proceed
  const canContinue = !!startLocation && !!destinationLocation;
  return {
    startLocationName:  startLocation?.address || '',
    destinationLocationName: destinationLocation?.address || '',
    handlePressStart,
    handlePressDestination,
    handleContinue,
    canContinue,
    recentRides,
    handleSelectRecentRide,
  };
};

import { useState, useCallback, useRef, useEffect, useMemo } from 'react';
import { useAppNavigation } from '@/hooks/useAppNavigation';
import { useRidePublishStore } from '@/store/useRidePublishStore';
import { useLocationStore, Location } from '@/store/useLocationStore';
import { locationService, OlaPrediction } from '@/serviceManager/locationService';
import { showNotification } from '@/components/organisms/GlobalNotification/GlobalNotification';
import Toast from 'react-native-toast-message';
import { NotificationType } from '@/constants/enums';
import { useLocale } from '@/constants/localization';
import {
  snapToRoute,
  buildRouteLineGeoJSON,
  buildConnectorLine,
  SnapResult,
} from '@/utils/routeSnap';
import { getBoundingBox } from '@/utils/polyline';
import { LocationOption } from '@/components/organisms/MiddleStopSearchOverlay';
import debounce from 'lodash/debounce';
import throttle from 'lodash/throttle';
import { Logger } from '@/utils/logger';

const EMPTY_HISTORY: Location[] = [];

export interface MiddleStopMapLocation {
  id: string;
  name: string;
  address?: string;
  latitude: number;
  longitude: number;
  distanceFromRoute?: number;
}

export const useMiddleStopMap = () => {
  const navigation = useAppNavigation();
  const { middleStopMap: t, middleStops: tStops } = useLocale();

  // Store data
  const {
    selectedRoute,
    startLocation,
    destinationLocation,
    middleStops,
  } = useRidePublishStore();

  const contextKey = 'publish_middleStop';
  const addSearchHistory = useLocationStore(s => s.addSearchHistory);
  const history = useLocationStore(s => s.history[contextKey] || EMPTY_HISTORY);

  // UI state
  const [isSearching, setIsSearching] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<MiddleStopMapLocation[]>([]);
  const [selectedLocation, setSelectedLocation] = useState<MiddleStopMapLocation | null>(null);
  const [snapResult, setSnapResult] = useState<SnapResult | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const mapRef = useRef<any>(null);
  const cameraRef = useRef<any>(null);
  const zoomRef = useRef(14);
  const [isMoving, setIsMoving] = useState(false);
  const [isReverseGeocoding, setIsReverseGeocoding] = useState(false);

  // Route coordinates from the selected route in the store
  const routeCoordinates = useMemo<[number, number][]>(
    () => selectedRoute?.coordinates ?? [],
    [selectedRoute],
  );

  // Map bounds to fit the route
  const routeBounds = useMemo(
    () => getBoundingBox(routeCoordinates),
    [routeCoordinates],
  );

  // Initial camera center from route bounds
  const initialCenter = useMemo<[number, number]>(() => {
    if (routeBounds[0] === 0 && routeBounds[2] === 0) {
      return [77.5946, 12.9716]; // Fallback: Bengaluru
    }
    return [
      (routeBounds[0] + routeBounds[2]) / 2,
      (routeBounds[1] + routeBounds[3]) / 2,
    ];
  }, [routeBounds]);

  // Route title string
  const routeTitle = useMemo(() => {
    const startName = startLocation?.name || startLocation?.address || '';
    const destName = destinationLocation?.name || destinationLocation?.address || '';
    return `${startName} → ${destName}`;
  }, [startLocation, destinationLocation]);

  // GeoJSON for the main route polyline
  const routeGeoJSON = useMemo(
    () => (routeCoordinates.length >= 2
      ? buildRouteLineGeoJSON(routeCoordinates)
      : null),
    [routeCoordinates],
  );

  // GeoJSON for the dashed connector line (selected → snapped)
  const connectorGeoJSON = useMemo(() => {
    if (!selectedLocation || !snapResult) return null;
    const from: [number, number] = [selectedLocation.longitude, selectedLocation.latitude];
    return buildConnectorLine(from, snapResult.snappedPoint);
  }, [selectedLocation, snapResult]);

  // Debounced search using OLA Autocomplete
  const debouncedSearch = useRef(
    debounce(async (query: string) => {
      if (query.trim().length <= 2) {
        setSearchResults([]);
        return;
      }
      setIsLoading(true);
      try {
        const predictions = await locationService.autocomplete(query);
        const mapped: MiddleStopMapLocation[] = predictions.map((p: OlaPrediction) => {
          const loc: MiddleStopMapLocation = {
            id: p.place_id,
            name: p.structured_formatting.main_text,
            address: p.description,
            latitude: p.geometry.location.lat,
            longitude: p.geometry.location.lng,
          };
          // Pre-compute distance from route for each result
          if (routeCoordinates.length >= 2) {
            const snap = snapToRoute(
              [loc.longitude, loc.latitude],
              routeCoordinates,
            );
            loc.distanceFromRoute = snap.distanceKm;
          }
          return loc;
        });
        // Sort results: closest to route first
        mapped.sort((a, b) => (a.distanceFromRoute ?? 99) - (b.distanceFromRoute ?? 99));
        setSearchResults(mapped);
      } catch (error) {
        Logger.error('[MiddleStopMap] debouncedSearch error:', error);
        setSearchResults([]);
      } finally {
        setIsLoading(false);
      }
    }, 500),
  ).current;

  useEffect(() => {
    debouncedSearch(searchQuery);
  }, [searchQuery, debouncedSearch]);

  // Reverse geocode initial center when search overlay is closed and no location is selected yet
  useEffect(() => {
    if (!isSearching && !selectedLocation && initialCenter) {
      const initGeocode = async () => {
        const [longitude, latitude] = initialCenter;
        setIsReverseGeocoding(true);
        try {
          const locationData = await locationService.reverseGeocode(latitude, longitude);
          const mapped: MiddleStopMapLocation = {
            id: `picked-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
            name: locationData.name || 'Selected Location',
            address: locationData.address || 'Custom coordinates',
            latitude,
            longitude,
          };
          setSelectedLocation(mapped);

          if (routeCoordinates.length >= 2) {
            const result = snapToRoute(
              [longitude, latitude],
              routeCoordinates,
            );
            setSnapResult(result);
          }
        } catch (e) {
          console.error(e);
        } finally {
          setIsReverseGeocoding(false);
        }
      };
      initGeocode();
    }
  }, [isSearching, selectedLocation, initialCenter, routeCoordinates]);

  const [isMapMounted, setIsMapMounted] = useState(true);

  const handleBackPress = useCallback(() => {
    if (isSearching && selectedLocation) {
      setIsSearching(false);
    } else {
      navigation.pop();
    }
  }, [isSearching, selectedLocation, navigation]);

  // Handle search input change
  const handleChangeSearch = useCallback((query: string) => {
    setSearchQuery(query);
  }, []);

  // Handle search press (show search overlay)
  const handleSearchPress = useCallback(() => {
    setIsSearching(true);
  }, []);

  // Handle location selection from search results
  const handleSelectLocation = useCallback(
    (loc: LocationOption) => {
      if (loc.latitude === undefined || loc.longitude === undefined) return;

      const mapped: MiddleStopMapLocation = {
        id: loc.id,
        name: loc.name,
        address: loc.address,
        latitude: loc.latitude,
        longitude: loc.longitude,
        distanceFromRoute: loc.distanceFromRoute,
      };

      setSelectedLocation(mapped);
      setIsSearching(false);
      setSearchQuery('');
      setSearchResults([]);

      // Compute snap
      if (routeCoordinates.length >= 2) {
        const result = snapToRoute(
          [loc.longitude, loc.latitude],
          routeCoordinates,
        );
        setSnapResult(result);

        if (!result.isWithinThreshold) {
          showNotification(
            NotificationType.WARNING,
            t.tooFarFromRoute,
            t.tooFarFromRouteMsg,
          );
        }
      }

      // Move camera to the selected location
      setTimeout(() => {
        cameraRef.current?.setStop({
          center: [loc.longitude, loc.latitude],
          zoom: 14,
          duration: 1000,
        });
      }, 100);
    },
    [routeCoordinates, t],
  );

  // Handle selecting from history
  const handleSelectHistory = useCallback(
    (loc: Location) => {
      const mapped: LocationOption = {
        id: loc.id,
        name: loc.name || '',
        address: loc.address,
        latitude: loc.latitude,
        longitude: loc.longitude,
      };
      handleSelectLocation(mapped);
    },
    [handleSelectLocation],
  );

  // Distance text for display
  const distanceText = useMemo(() => {
    if (!snapResult) return '';
    return t.distanceFromRoute.replace('{{distance}}', String(snapResult.distanceKm));
  }, [snapResult, t]);

  // Whether the confirm button is enabled
  const canConfirm = useMemo(
    () => !!selectedLocation && (snapResult?.isWithinThreshold ?? false),
    [selectedLocation, snapResult],
  );

  // Handle confirm — write directly to store and pop back to MiddleStops.
  // Running duplicate-check + distance-sort here so we never need to pass params.
  const handleConfirm = useCallback(async () => {
    if (!selectedLocation || !canConfirm || !startLocation) return;

    const locationForStore: Location = {
      id: selectedLocation.id,
      name: selectedLocation.name,
      address: selectedLocation.address || '',
      latitude: selectedLocation.latitude,
      longitude: selectedLocation.longitude,
    };

    addSearchHistory(locationForStore, contextKey);

    // Duplicate check
    const currentStops = useRidePublishStore.getState().middleStops;
    const isStartDuplicate =
      startLocation.latitude === locationForStore.latitude &&
      startLocation.longitude === locationForStore.longitude;
    const isDestDuplicate =
      destinationLocation != null &&
      destinationLocation.latitude === locationForStore.latitude &&
      destinationLocation.longitude === locationForStore.longitude;
    const isAlreadyStop = currentStops.some(
      (s) =>
        s.id === locationForStore.id ||
        (s.latitude === locationForStore.latitude && s.longitude === locationForStore.longitude) ||
        (s.name && s.name === locationForStore.name),
    );

    if (isStartDuplicate || isDestDuplicate || isAlreadyStop) {
      showNotification(
        NotificationType.WARNING,
        tStops.duplicateStopTitle,
        tStops.duplicateStopMsg,
      );
      return;
    }

    // Distance-sort: calculate distance from start then insert sorted
    let stopWithDistance: Location & { distanceFromStart?: number } = locationForStore;
    try {
      const results = await locationService.getDirections(
        startLocation.latitude,
        startLocation.longitude,
        locationForStore.latitude,
        locationForStore.longitude,
      );
      if (results && results.length > 0) {
        const mainRoute = results[0];
        const distanceMeters: number =
          mainRoute.distance ??
          (mainRoute.legs?.reduce((acc: number, leg: any) => acc + (leg.distance || 0), 0) || 0);
        stopWithDistance = { ...locationForStore, distanceFromStart: distanceMeters };
      }
    } catch {
      // Fall back to unsorted insertion if distance lookup fails
    }

    const latest = useRidePublishStore.getState().middleStops;
    if (!latest.some((s) => s.id === locationForStore.id)) {
      const sorted = [...latest, stopWithDistance].sort(
        (a, b) => ((a as any).distanceFromStart ?? 0) - ((b as any).distanceFromStart ?? 0),
      );
      useRidePublishStore.getState().setMiddleStops(sorted);
    }

    navigation.pop();
  }, [selectedLocation, canConfirm, startLocation, destinationLocation, navigation, addSearchHistory, contextKey, t]);

  const handleZoom = useCallback((increment: number) => {
    const newZoom = Math.min(Math.max(zoomRef.current + increment, 4), 20);
    zoomRef.current = newZoom;
    cameraRef.current?.setStop({
      zoom: newZoom,
      duration: 300,
    });
  }, []);

  const handleZoomIn = useCallback(() => handleZoom(1), [handleZoom]);
  const handleZoomOut = useCallback(() => handleZoom(-1), [handleZoom]);

  const handleRegionWillChange = useCallback(() => {
    setIsMoving(true);
    Toast.hide();
  }, []);

  // Throttled snap & selectedLocation coordinate update during dragging to ensure 60fps UI performance
  const throttledRegionIsChanging = useRef(
    throttle((longitude: number, latitude: number, coords: [number, number][]) => {
      if (coords.length >= 2) {
        const result = snapToRoute(
          [longitude, latitude],
          coords,
        );
        setSnapResult(result);
      }

      setSelectedLocation(prev => {
        if (!prev) return null;
        if (prev.latitude === latitude && prev.longitude === longitude) return prev;
        return {
          ...prev,
          latitude,
          longitude,
        };
      });
    }, 120)
  ).current;

  useEffect(() => {
    return () => {
      throttledRegionIsChanging.cancel?.();
    };
  }, [throttledRegionIsChanging]);

  const handleRegionIsChanging = useCallback((event: any) => {
    if (isSearching) return;

    const viewState = event?.nativeEvent || event;
    if (!viewState?.center) return;

    const [longitude, latitude] = viewState.center;
    throttledRegionIsChanging(longitude, latitude, routeCoordinates);
  }, [isSearching, routeCoordinates, throttledRegionIsChanging]);

  const handleRegionChangeComplete = useCallback(async (event: any) => {
    setIsMoving(false);
    throttledRegionIsChanging.cancel?.();

    const viewState = event?.nativeEvent || event;
    if (!viewState?.center) return;

    const [longitude, latitude] = viewState.center;
    const currentZoom = viewState.zoom;

    if (currentZoom !== undefined) {
      zoomRef.current = currentZoom;
    }

    if (isSearching) return;

    // 1. UPDATE SNAP RESULT IMMEDIATELY (Instant feedback!)
    if (routeCoordinates.length >= 2) {
      const result = snapToRoute(
        [longitude, latitude],
        routeCoordinates,
      );
      setSnapResult(result);
    }

    setIsReverseGeocoding(true);
    try {
      const locationData = await locationService.reverseGeocode(latitude, longitude);

      const mapped: MiddleStopMapLocation = {
        id: selectedLocation?.id && selectedLocation.id.startsWith('picked-')
          ? selectedLocation.id
          : `picked-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
        name: locationData.name || 'Selected Location',
        address: locationData.address || 'Custom coordinates',
        latitude,
        longitude,
      };

      setSelectedLocation(mapped);

      if (routeCoordinates.length >= 2) {
        const result = snapToRoute(
          [longitude, latitude],
          routeCoordinates,
        );
        setSnapResult(result);

        if (!result.isWithinThreshold) {
          showNotification(
            NotificationType.WARNING,
            t.tooFarFromRoute,
            t.tooFarFromRouteMsg,
          );
        } else {
          Toast.hide();
        }
      }
    } catch (error) {
      console.error('Failed to reverse geocode center:', error);
    } finally {
      setIsReverseGeocoding(false);
    }
  }, [isSearching, routeCoordinates, t, selectedLocation, throttledRegionIsChanging]);

  // Handle map press to select coordinates directly (places / moves the marker)
  const handleMapPress = useCallback(async (feature: any) => {
    if (!feature || !feature.geometry || !feature.geometry.coordinates) return;
    const [longitude, latitude] = feature.geometry.coordinates;

    Toast.hide();

    // 1. UPDATE SNAP RESULT IMMEDIATELY (Instant feedback!)
    if (routeCoordinates.length >= 2) {
      const result = snapToRoute(
        [longitude, latitude],
        routeCoordinates,
      );
      setSnapResult(result);
    }

    setIsReverseGeocoding(true);
    try {
      const locationData = await locationService.reverseGeocode(latitude, longitude);

      const mapped: MiddleStopMapLocation = {
        id: `picked-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
        name: locationData.name || 'Selected Location',
        address: locationData.address || 'Custom coordinates',
        latitude,
        longitude,
      };

      setSelectedLocation(mapped);
      setIsSearching(false);

      if (routeCoordinates.length >= 2) {
        const result = snapToRoute(
          [longitude, latitude],
          routeCoordinates,
        );
        setSnapResult(result);

        if (!result.isWithinThreshold) {
          showNotification(
            NotificationType.WARNING,
            t.tooFarFromRoute,
            t.tooFarFromRouteMsg,
          );
        } else {
          Toast.hide();
        }
      }

      // Smoothly pan camera to selected location
      cameraRef.current?.setStop({
        center: [longitude, latitude],
        duration: 500,
      });
    } catch (error) {
      console.error('Failed to reverse geocode coordinate:', error);
    } finally {
      setIsReverseGeocoding(false);
    }
  }, [routeCoordinates, t]);

  // Middle stops count for the footer badge
  const stopsCount = middleStops.length;

  return {
    // State
    isSearching,
    isLoading,
    isReverseGeocoding,
    isMoving,
    searchQuery,
    searchResults,
    selectedLocation,
    snapResult,
    canConfirm,

    // Display data
    routeTitle,
    distanceText,
    stopsCount,
    history,
    initialCenter,

    // GeoJSON data for the map
    routeGeoJSON,
    connectorGeoJSON,
    routeBounds,
    routeCoordinates,

    // Refs
    mapRef,
    cameraRef,

    // Start / Destination for markers
    startLocation,
    destinationLocation,

    // Handlers
    handleBackPress,
    handleSearchPress,
    handleChangeSearch,
    handleSelectLocation,
    handleSelectHistory,
    handleConfirm,
    handleZoomIn,
    handleZoomOut,
    handleRegionWillChange,
    handleRegionIsChanging,
    handleRegionChangeComplete,
    handleMapPress,
    isMapMounted,
  };
};

import { useCallback, useEffect, useState } from 'react';
import { useRoute } from '@react-navigation/native';
import { useRidePublishStore } from '@/store/useRidePublishStore';
import { locationService } from '@/serviceManager/locationService';
import { useAppNavigation } from '@/hooks/useAppNavigation'; // ensure custom navigation hook is used
import { decodePolyline, getBoundingBox } from '@/utils/polyline';

export const useMiddleStops = () => {
  const navigation = useAppNavigation(); // use custom navigation hook per guidelines
  const route = useRoute();
  const params = route.params as any;

  const { 
    startLocation, 
    destinationLocation, 
    middleStops,
    setMiddleStops,
    removeMiddleStop,
    setRouteDetails,
    selectedRoute,
    setSelectedRoute,
  } = useRidePublishStore();

  const [isSorting, setIsSorting] = useState(false);
  const [totalDistanceMeters, setTotalDistanceMeters] = useState<number | null>(null);


  const sortedStops = middleStops; // Already sorted in store
  console.log('sortedStops', sortedStops);
  const handleBackPress = useCallback(() => {
    navigation.goBack();
  }, [navigation]);

  const handleAddStop = useCallback(() => {
    navigation.push('MiddleStopMap');
  }, [navigation]);

  const handleRemoveStop = useCallback((id: string) => {
    removeMiddleStop(id);
  }, [removeMiddleStop]);

  const handleContinuePress = useCallback(async () => {

    if (!startLocation || !destinationLocation) {
      navigation.navigate('DateSelection' as any);
      return;
    }

    setIsSorting(true);
    try {
      const waypoints = middleStops.length > 0 
        ? middleStops.map(s => `${s.latitude},${s.longitude}`).join('|')
        : undefined;

      const results = await locationService.getDirections(
        startLocation.latitude,
        startLocation.longitude,
        destinationLocation.latitude,
        destinationLocation.longitude,
        waypoints
      );

      if (results && results.length > 0) {
        const mainRoute = results[0];
        const legs = mainRoute.legs?.map((leg, i) => ({
          distanceMeters: leg.distance,
          durationSeconds: leg.duration,
          startAddress: i === 0 ? startLocation.name : (middleStops[i - 1]?.name || 'Stop'),
          endAddress: i === (mainRoute.legs?.length || 0) - 1 ? destinationLocation.name : (middleStops[i]?.name || 'Stop'),
        })) || [];

        const totalDistanceMeters = mainRoute.distance ?? legs.reduce((acc, leg) => acc + leg.distanceMeters, 0);
        const totalDurationSeconds = mainRoute.duration ?? legs.reduce((acc, leg) => acc + leg.durationSeconds, 0);

        const details = {
          totalDistanceMeters,
          totalDurationSeconds,
          legs,
        };
        setRouteDetails(details);
        // Store total distance for display in UI
        setTotalDistanceMeters(totalDistanceMeters);

        // Update selectedRoute in store to route through the middle stops
        const polyline = mainRoute.overview_polyline || mainRoute.geometry || '';
        const coordinates = decodePolyline(polyline, 1e5);
        const bounds = getBoundingBox(coordinates);

        if (selectedRoute) {
          setSelectedRoute({
            ...selectedRoute,
            coordinates,
            bounds,
            polylineString: polyline,
            uiData: {
              ...selectedRoute.uiData,
              distance: `${(totalDistanceMeters / 1000).toFixed(1)} km`,
              duration: Math.round(totalDurationSeconds / 60) > 60 
                ? `${Math.floor(Math.round(totalDurationSeconds / 60) / 60)} hr ${Math.round(totalDurationSeconds / 60) % 60} min` 
                : `${Math.round(totalDurationSeconds / 60)} min`,
            },
          });
        }
      } else {
        setRouteDetails(null as any);
        setTotalDistanceMeters(null);
      }
    } catch (error) {
      console.error('Failed to calculate full route details:', error);
      setRouteDetails(null as any);
    } finally {
      setIsSorting(false);
      if (params?.returnTo === 'SummaryPublish') {
        (navigation.navigate as any)('SummaryPublish');
      } else {
        (navigation.navigate as any)('DateSelection');
      }
    }
  }, [navigation, setRouteDetails, startLocation, destinationLocation, middleStops, params]);

  // Compute total distance for display as soon as stops are updated
  useEffect(() => {
    const computeTotal = async () => {
      if (!startLocation || !destinationLocation) {
        setTotalDistanceMeters(null);
        return;
      }
      try {
        const waypoints = middleStops.length > 0 ? middleStops.map(s => `${s.latitude},${s.longitude}`).join('|') : undefined;
        const res = await locationService.getDirections(
          startLocation.latitude,
          startLocation.longitude,
          destinationLocation.latitude,
          destinationLocation.longitude,
          waypoints
        );
        if (res && res.length > 0) {
          const route = res[0];
          const legs = route.legs?.map((leg) => ({ distance: leg.distance })) || [];
          const total = route.distance ?? legs.reduce((a, l) => a + (l.distance || 0), 0);
          setTotalDistanceMeters(total);

          // Dynamically update the selectedRoute in store to pass through waypoints in real-time
          const polyline = route.overview_polyline || route.geometry || '';
          const coordinates = decodePolyline(polyline, 1e5);
          const bounds = getBoundingBox(coordinates);

          const currentRoute = useRidePublishStore.getState().selectedRoute;
          if (currentRoute) {
            useRidePublishStore.getState().setSelectedRoute({
              ...currentRoute,
              coordinates,
              bounds,
              polylineString: polyline,
              uiData: {
                ...currentRoute.uiData,
                distance: `${(total / 1000).toFixed(1)} km`,
              },
            });
          }
        } else {
          setTotalDistanceMeters(null);
        }
      } catch (e) {
        console.error('Failed to compute total distance', e);
        setTotalDistanceMeters(null);
      }
    };
    computeTotal();
  }, [startLocation, destinationLocation, middleStops]);

  const startDistanceText = '0 km';
  const destinationDistanceText = totalDistanceMeters !== null ? `${(totalDistanceMeters / 1000).toFixed(1)} km` : undefined;

  return {
    startLocation: startLocation?.name || startLocation?.address || 'Pick Start Location',
    destination: destinationLocation?.name || destinationLocation?.address || 'Pick Destination',
    startLocationRaw: startLocation,
    destinationLocationRaw: destinationLocation,
    middleStops: sortedStops.map(s => ({
      id: s.id,
      name: s.name || s.address || 'Unknown Stop',
      distanceText: (s as any).distanceFromStart
        ? `${((s as any).distanceFromStart / 1000).toFixed(1)} km from start`
        : undefined,
    })),
    middleStopsRaw: sortedStops,
    startDistanceText,
    destinationDistanceText,
    handleBackPress,
    handleAddStop,
    handleRemoveStop,
    handleContinuePress,
    isLoading: isSorting,
  };
};

import { useAppNavigation } from '@/hooks/useAppNavigation';
import { useState, useCallback, useMemo, useEffect } from 'react';
import { useRoute, RouteProp, useIsFocused } from '@react-navigation/native';
import { useLocale } from '@/constants/localization';
import { RootStackParamList } from '@/navigation/types.d';
import { useRidePublishStore } from '@/store/useRidePublishStore';
import { useVehicleStore } from '@/store/useVehicleStore';

export const useSeatSelection = () => {
  const navigation = useAppNavigation();
  const route = useRoute<RouteProp<RootStackParamList, 'SeatSelection'>>();
  const isFocused = useIsFocused();
  const { selectSeat: tSelect, seatSelection: tPublish } = useLocale();

  const flow = route.params?.flow || 'publish';
  const returnTo = (route.params as any)?.returnTo;
  const t = flow === 'book' ? tSelect : tPublish;

  const { 
    selectedSeatIds, 
    setSelectedSeatIds, 
    publishVehicleType, 
    setPublishVehicleType,
    setVehicleDetails,
    setSeatCount,
    setVehicleId,
    vehicleId,
  } = useRidePublishStore();

  const { vehicles, selectedVehicleId, setSelectedVehicle } = useVehicleStore();
  const [selectedSeats, setSelectedSeats] = useState<Set<string | number>>(new Set(selectedSeatIds));

  const handleVehicleSelect = useCallback((id: string) => {
    const vehicle = vehicles.find(v => v.id === id);
    if (vehicle) {
      setSelectedVehicle(id);
      setVehicleId(id);
      setPublishVehicleType(vehicle.seater);
      setVehicleDetails({
        company: vehicle.company,
        model: vehicle.model,
        numberPlate: vehicle.numberPlate,
        type: vehicle.type,
        color: vehicle.color,
        seater: vehicle.seater,
      });
      setSelectedSeats(new Set());
    }
  }, [vehicles, setSelectedVehicle, setVehicleId, setPublishVehicleType, setVehicleDetails]);

  useEffect(() => {
    if (isFocused && vehicles.length > 0) {
      if (!selectedVehicleId) {
        handleVehicleSelect(vehicles[0].id);
      } else {
        // If one is selected, ensure publish store is synced with it
        const vehicle = vehicles.find(v => v.id === selectedVehicleId);
        if (vehicle && (publishVehicleType !== vehicle.seater || vehicleId !== vehicle.id)) {
          setPublishVehicleType(vehicle.seater);
          setVehicleId(vehicle.id);
          setVehicleDetails({
            company: vehicle.company,
            model: vehicle.model,
            numberPlate: vehicle.numberPlate,
            type: vehicle.type,
            color: vehicle.color,
            seater: vehicle.seater,
          });
        }
      }
    }
  }, [isFocused, vehicles, selectedVehicleId, handleVehicleSelect, publishVehicleType, vehicleId, setVehicleId, setPublishVehicleType, setVehicleDetails]);

  const onSeatPress = useCallback((id: string | number) => {
    setSelectedSeats((prev) => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  }, []);

  const onAddNewVehicle = useCallback(() => {
    (navigation.navigate as any)('VehicleDetails');
  }, [navigation]);

  const seatIdsLabel = useMemo(() => {
    return Array.from(selectedSeats).join(', ');
  }, [selectedSeats]);

  const onBackPress = useCallback(() => {
    navigation.goBack();
  }, [navigation]);

  const onContinue = useCallback(() => {
    if (selectedSeats.size > 0 && selectedVehicleId) {
      if (flow === 'publish') {
        setSeatCount(selectedSeats.size);
        setSelectedSeatIds(Array.from(selectedSeats) as number[]);
        setPublishVehicleType(publishVehicleType);

        if (returnTo) {
          (navigation.navigate as any)(returnTo, {
            returnTo: (route.params as any)?.nextReturnTo,
          });
        } else {
          (navigation.navigate as any)('PriceSelection');
        }
      } else {
        // For booking, either go back or to a payment screen
        navigation.goBack();
      }
    }
  }, [selectedSeats, selectedVehicleId, navigation, flow, setSeatCount, setSelectedSeatIds, setPublishVehicleType, publishVehicleType, returnTo]);

  return {
    flow,
    selectedSeats,
    vehicleType: publishVehicleType,
    seatIdsLabel,
    onSeatPress,
    vehicles,
    selectedVehicleId,
    onVehicleSelect: handleVehicleSelect,
    onAddNewVehicle,
    onBackPress,
    onContinue,
    t,
  };
};

import { useAppNavigation } from '@/hooks/useAppNavigation';
import { useCallback } from 'react';
import { addSeconds, format } from 'date-fns';
import rideService, { PublishRidePayload, RouteStop } from '@/serviceManager/rideService';
import { roundToNearest } from '@/utils/pricing';
import { useMyRidesStore } from '@/store/useMyRidesStore';
import { useTranslation } from '@/hooks/useTranslation';
import { showNotification } from '@/components/organisms/GlobalNotification/GlobalNotification';
import { NotificationType } from '@/constants/enums';
import { getErrorMessage } from '@/utils/error';
import { storage } from '@/utils/storage';

export const useSummaryActions = (publishStore: any, setIsPublishing: (v: boolean) => void) => {
  const navigation = useAppNavigation();
  const { t } = useTranslation();
  const { addDraft, removeDraft } = useMyRidesStore();

  const {
    startLocation,
    destinationLocation,
    middleStops,
    departureDate,
    departureTime,
    seatCount,
    selectedSeatIds,
    publishVehicleType,
    vehicleDetails,
    vehicleId,
    preferences,
    price,
    fullJourneyPrice,
    frontSeatPrice,
    premiumEnabled,
    premiumPercentage,
    routeDetails,
    segmentPrices,
    clearPublishState,
    selectedRoute,
    editingDraftId,
    requestType,
  } = publishStore;

  const handlePublish = useCallback(async () => {
    if (!startLocation || !destinationLocation || !departureDate || !departureTime || !vehicleId) return;
    setIsPublishing(true);
    try {
      const dateObj = new Date(departureDate);
      const [time, ampm] = departureTime.split(' ');
      const [hours, minutes] = time.split(':').map(Number);
      let h = hours;
      if (ampm === 'PM' && h !== 12) h += 12;
      if (ampm === 'AM' && h === 12) h = 0;
      dateObj.setHours(h, minutes, 0, 0);
      const startTime = format(dateObj, "yyyy-MM-dd'T'HH:mm:ss");
      const endDateObj = addSeconds(dateObj, routeDetails?.totalDurationSeconds || 0);
      const endTime = format(endDateObj, "yyyy-MM-dd'T'HH:mm:ss");

      const offeredSeatIds = selectedSeatIds;

      const allStops = [startLocation, ...middleStops, destinationLocation];
      let cumulativePrice = 0;
      let cumulativeFrontSeatPrice = 0;

      const routeStops: RouteStop[] = allStops.map((stop, index) => {
        const segmentId = index > 0 ? `seg-${index - 1}` : '';
        const segmentPrice = index > 0 
          ? roundToNearest(Number(segmentPrices[segmentId]) || (price / (allStops.length - 1)), 10) 
          : 0;
        const frontSeatSegmentPrice = premiumEnabled ? roundToNearest(segmentPrice * (1 + (premiumPercentage || 0) / 100), 10) : segmentPrice;

        cumulativePrice += segmentPrice;
        cumulativeFrontSeatPrice += frontSeatSegmentPrice;

        const stopLeg = index > 0 && routeDetails?.legs ? routeDetails.legs[index - 1] : null;

        let arrivalTime = startTime;
        if (index > 0 && routeDetails?.legs) {
          let accumulatedDuration = 0;
          for (let i = 0; i < index; i++) {
            accumulatedDuration += routeDetails.legs[i].durationSeconds;
          }
          arrivalTime = format(addSeconds(dateObj, accumulatedDuration), "yyyy-MM-dd'T'HH:mm:ss");
        }

        return {
          name: stop.address,
          lat: stop.latitude,
          lon: stop.longitude,
          sequence: index + 1,
          distanceFromPreviousStop: stopLeg ? stopLeg.distanceMeters / 1000 : 0,
          priceFromPreviousStop: cumulativePrice,
          frontSeatPriceFromPreviousStop: cumulativeFrontSeatPrice,
          arrivalTime,
        };
      });

      const payload: PublishRidePayload = {
        vehicleId,
        startTime,
        endTime,
        offeredSeatIds,
        routePath: selectedRoute?.polylineString || '',
        routeStops,
        fullJourneyPrice: String(fullJourneyPrice),
        frontSeatPrice: String(frontSeatPrice),
      };
      await rideService.publishRide(payload);

      try {
        const existingRidesRaw = storage.getString('recent_published_rides');
        let recentRides = existingRidesRaw ? JSON.parse(existingRidesRaw) : [];

        const currentRide = {
          startLocation,
          destinationLocation,
          middleStops,
          routeDetails,
          selectedRoute,
          seatCount,
          selectedSeatIds,
          vehicleId,
          publishVehicleType,
          vehicleDetails,
          preferences,
          price,
          fullJourneyPrice,
          frontSeatPrice,
          premiumEnabled,
          premiumPercentage,
          segmentPrices,
          requestType,
          departureDate,
          departureTime,
        };

        recentRides.unshift(currentRide);
        recentRides = recentRides.slice(0, 5);

        storage.set('recent_published_rides', JSON.stringify(recentRides));
      } catch (err) {
        console.error('[MMKV] Failed to save recent ride:', err);
      }

      if (editingDraftId) {
        removeDraft(editingDraftId);
      }

      navigation.reset({
        index: 1,
        routes: [
          { name: 'BookRideInfo' },
          { name: 'PublishSuccess' },
        ],
      } as any);
      clearPublishState();
    } catch (error: any) {
      console.error('Publish failed:', error);
      showNotification(
        NotificationType.ERROR,
        t('notification.defaultErrorTitle'),
        getErrorMessage(error, t('notification.defaultErrorMessage'))
      );
    } finally {
      setIsPublishing(false);
    }
  }, [
    navigation, startLocation, destinationLocation, middleStops, departureDate, departureTime, 
    selectedSeatIds, routeDetails, segmentPrices, price, clearPublishState,
    selectedRoute, removeDraft, editingDraftId, premiumEnabled, premiumPercentage, fullJourneyPrice, 
    frontSeatPrice, vehicleId, setIsPublishing
  ]);

  const handleSave = useCallback(() => {
    const currentState = {
      startLocation,
      destinationLocation,
      middleStops,
      departureDate,
      departureTime,
      seatCount,
      selectedSeatIds,
      publishVehicleType,
      vehicleDetails,
      vehicleId,
      preferences,
      price,
      fullJourneyPrice,
      frontSeatPrice,
      premiumEnabled,
      premiumPercentage,
      routeDetails,
      segmentPrices,
      selectedRoute,
      requestType,
    };

    addDraft(currentState, editingDraftId);
    clearPublishState();
    (navigation.navigate as any)('MyRides', { tab: 'drafts' });
  }, [
    addDraft, editingDraftId, navigation, startLocation, destinationLocation, middleStops, 
    departureDate, departureTime, seatCount, selectedSeatIds, publishVehicleType, vehicleDetails, 
    preferences, price, routeDetails, segmentPrices, selectedRoute, requestType, clearPublishState
  ]);

  return {
    handlePublish,
    handleSave,
  };
};

import { useMemo } from 'react';
import { getColorLabel } from '@/constants/ride';
import { useTravelPrefStore } from '@/store/useTravelPrefStore';
import { useLocale } from '@/constants/localization';

export const useSummaryMappers = (publishStore: any) => {
  const {
    departureDate,
    seatCount,
    price,
    vehicleDetails,
    requestType,
  } = publishStore;

  const { preferences: storedPrefs } = useTravelPrefStore();
  const { travelPreferences: pt, summaryPublish: spt, rideDetails: rdt } = useLocale();

  const formattedDate = useMemo(() => {
    if (!departureDate) return null;
    const date = new Date(departureDate);
    return date.toLocaleDateString('en-GB', {
      day: 'numeric',
      month: 'short',
      year: 'numeric',
    });
  }, [departureDate]);

  const vehicleData = useMemo(() => {
    if (!vehicleDetails) return null;
    const colorLabel = getColorLabel(vehicleDetails.color);
    return {
      name: `${vehicleDetails.company} ${vehicleDetails.model}`,
      subText: `${vehicleDetails.seater}-Seater • ${colorLabel}`,
      numberplate: vehicleDetails.numberPlate,
      icon: vehicleDetails.type === 'bike' ? 'motorcycle' : 'directions-car',
    };
  }, [vehicleDetails]);

  const pricingData = useMemo(() => ({
    seatCount,
    pricePerSeat: `₹${price}`,
  }), [seatCount, price]);

  const preferencesData = useMemo(() => {
    const prefs = {
      nonSmoking: storedPrefs?.nonSmoking ?? true,
      womenOnly: storedPrefs?.womenOnly ?? false,
      musicPreference: storedPrefs?.musicPreference ?? 'Pop',
      luggageAllowed: storedPrefs?.luggageAllowed ?? true,
      petFriendly: storedPrefs?.petFriendly ?? false,
      waitingTime: storedPrefs?.waitingTime ?? 10,
      manualApproval: requestType === 'review',
    };


    const data = [];

    if (prefs.nonSmoking) {
      data.push({ id: 'smoking', label: pt.nonSmoking, icon: 'smoke-free' });
    }

    if (prefs.womenOnly) {
      data.push({ id: 'women', label: pt.womenOnly, icon: 'female' });
    }

    if (prefs.manualApproval) {
      data.push({ id: 'approval', label: rdt.approvalRequired, icon: 'verified-user' });
    } else {
      data.push({ id: 'approval', label: rdt.instantBooking, icon: 'flash-on' });
    }

    if (prefs.musicPreference) {
      data.push({ id: 'music', label: prefs.musicPreference, icon: 'library-music' });
    }

    if (prefs.luggageAllowed) {
      data.push({ id: 'luggage', label: pt.luggageAllowed, icon: 'luggage' });
    }

    if (prefs.petFriendly) {
      data.push({ id: 'pets', label: pt.petFriendly, icon: 'pets' });
    }

    if (prefs.waitingTime) {
      data.push({ id: 'waiting', label: `${prefs.waitingTime}m wait`, icon: 'timer' });
    }

    return data;
  }, [storedPrefs, pt, requestType, rdt]);

  return {
    formattedDate,
    vehicleData,
    pricingData,
    preferencesData,
  };
};

import { useAppNavigation } from '@/hooks/useAppNavigation';
import { useState } from 'react';
import { useSettingsStore } from '@/store/settings';
