import { showNotification } from '@/components/organisms/GlobalNotification/GlobalNotification';
import { NotificationType } from '@/constants/enums';
import { getErrorMessage } from '@/utils/error';

export const useSettings = () => {
  const navigation = useAppNavigation();
  const t = useLocale();

  const [isLogoutModalVisible, setIsLogoutModalVisible] = useState(false);
  const [isLoggingOut, setIsLoggingOut] = useState(false);

  // Appearance
  const themeMode = useSettingsStore(state => state.themeMode);
  const toggleTheme = useSettingsStore(state => state.toggleTheme);

  // Preference
  const language = useSettingsStore(state => state.language);
  const region = useSettingsStore(state => state.region);
  const setLanguage = useSettingsStore(state => state.setLanguage);

  // Notifications
  const pushNotifications = useSettingsStore(state => state.pushNotifications);
  const promoEmails = useSettingsStore(state => state.promoEmails);
  const rideReceipts = useSettingsStore(state => state.rideReceipts);
  const accountSecurity = useSettingsStore(state => state.accountSecurity);

  const togglePushNotifications = useSettingsStore(state => state.togglePushNotifications);
  const togglePromoEmails = useSettingsStore(state => state.togglePromoEmails);
  const toggleRideReceipts = useSettingsStore(state => state.toggleRideReceipts);

  // Auth / Logout
  const logout = useAuthStore(state => state.logout);

  const goBack = () => {
    navigation.goBack();
  };

  const showLogoutConfirmation = () => setIsLogoutModalVisible(true);
  const hideLogoutConfirmation = () => setIsLogoutModalVisible(false);

  const handleLogout = async () => {
    setIsLoggingOut(true);
    try {
      // 2. Call authService to notify backend and wipe Keychain + Zustand
      await authService.logout();

      // 3. Reset Navigation (if Zustand doesn't already catch it)
      navigation.reset({
        index: 0,
        routes: [{ name: 'Login' as never }],
      });
    } catch (e: any) {
      console.error('Logout failed in settings:', e);
      showNotification(
        NotificationType.ERROR,
        t.notification.defaultErrorTitle,
        getErrorMessage(e, t.notification.defaultErrorMessage)
      );
    } finally {
      setIsLoggingOut(false);
      setIsLogoutModalVisible(false);
    }
  };

  const handleToggleLanguage = () => {
    setLanguage(language === 'en' ? 'hi' : 'en');
  };

  return {
    t: t.settings,
    themeMode,
    toggleTheme,
    language,
    region,
    handleToggleLanguage,
    pushNotifications,
    togglePushNotifications,
    promoEmails,
    togglePromoEmails,
    rideReceipts,
    toggleRideReceipts,
    accountSecurity,
    goBack,
    handleLogout,
    isLogoutModalVisible,
    isLoggingOut,
    showLogoutConfirmation,
    hideLogoutConfirmation,
  };
};

import { AxiosError, AxiosResponse, InternalAxiosRequestConfig } from 'axios';
import { sanitizeHeaders } from '@/utils/networkSecurity';
import { Logger } from '@/utils/logger';

type HeaderRecord = Record<string, unknown>;
type JsonRecord = Record<string, unknown>;

const FORM_DATA_VALUE = '[FORM_DATA]';
const REDACTED_VALUE = '[REDACTED]';
const CONSOLE_REDACTED_KEY_PARTS = [
  'password',
  'otp',
  'secret',
  'credential',
  'key',
  'token',
  'authorization',
];

const getMethod = (method?: string): string => (method || 'GET').toUpperCase();

const hasToJSON = (value: unknown): value is { toJSON: () => unknown } =>
  typeof value === 'object' &&
  value !== null &&
  'toJSON' in value &&
  typeof value.toJSON === 'function';

const toHeaderRecord = (headers: unknown): HeaderRecord => {
  const headerSource = hasToJSON(headers) ? headers.toJSON() : headers;

  if (typeof headerSource !== 'object' || headerSource === null || Array.isArray(headerSource)) {
    return {};
  }

  return headerSource as HeaderRecord;
};

const getAuthorizationToken = (headers: unknown): string | undefined => {
  const headerRecord = toHeaderRecord(headers);
  const authorizationEntry = Object.entries(headerRecord).find(
    ([key]) => key.toLowerCase() === 'authorization',
  );

  return authorizationEntry ? String(authorizationEntry[1]) : undefined;
};

const isRecord = (value: unknown): value is JsonRecord =>
  typeof value === 'object' && value !== null && !Array.isArray(value);

const isFormDataValue = (value: unknown): boolean =>
  typeof FormData !== 'undefined' && value instanceof FormData;

const shouldRedactConsoleKey = (key: string): boolean => {
  const normalizedKey = key.toLowerCase();
  return CONSOLE_REDACTED_KEY_PARTS.some(part => normalizedKey.includes(part));
};

const redactConsoleData = (value: unknown): unknown => {
  if (value === null || value === undefined) return value;
  // if (isFormDataValue(value)) return FORM_DATA_VALUE;
  if (Array.isArray(value)) return value.map(item => redactConsoleData(item));
  if (!isRecord(value)) return value;

  return Object.entries(value).reduce<JsonRecord>((acc, [key, item]) => {
    acc[key] =  redactConsoleData(item);
    return acc;
  }, {});
};

export const logApiRequest = (config: InternalAxiosRequestConfig) => {
  if (!__DEV__) return;

  Logger.log('[API Request]', `${getMethod(config.method)} ${config.url}`);
  Logger.log('[API Token]', getAuthorizationToken(config.headers) || 'No token');
  Logger.log('[API Headers]', sanitizeHeaders(config.headers));
  Logger.log('[API Request Body]', redactConsoleData(config.data));
};

export const logApiResponse = (response: AxiosResponse) => {
  if (!__DEV__) return;

  Logger.log(
    '[API Response]',
    `${getMethod(response.config.method)} ${response.config.url} ${response.status}`,
  );
  Logger.log('[API Response Body]', redactConsoleData(response.data));
};

export const logApiError = (error: AxiosError) => {
  if (!__DEV__) return;

  Logger.error(
    '[API Error]',
    `${getMethod(error.config?.method)} ${error.config?.url} ${error.response?.status || 0}`,
  );
  Logger.error('[API Token]', getAuthorizationToken(error.config?.headers) || 'No token');
  Logger.error('[API Error Response]', redactConsoleData(error.response?.data || error.message));
};

import * as Keychain from 'react-native-keychain';
import { Platform } from 'react-native';
import apiClient from './apiClient';
import { API_ENDPOINTS } from '@/constants/apiEndpoints';
import { useAuthStore } from '@/store/useAuthStore';
import { getDeviceId } from '@/utils/deviceId';

export interface LoginResponse {
  status: string;
  message: string;
}

export interface VerifyOtpResponse {
  message: string;
  token: string;
  refreshToken: string;
  userId: string;
  existingUser: boolean;
  userProfileCompleted: boolean;
  status: string; // "success"
}

export const authService = {
  /**
   * Send OTP to the provided phone number for login.
   * @param phoneNumber 10-digit phone number
   * @param termandconditionSelected boolean flag for T&C acceptance
   */
  login: async (
    phoneNumber: string,
    termandconditionSelected: boolean = true
  ): Promise<{ status: number; data: LoginResponse }> => {
    try {
      const response = await apiClient.post<LoginResponse>(
        API_ENDPOINTS.AUTH.LOGIN,
        { phoneNumber, termandconditionSelected }
      );

      return {
        status: response.status,
        data: response.data,
      };
    } catch (error: any) {
      if (error.response) {
        throw new Error(error.response.data.message || 'Login failed');
      }
      throw new Error('Network error. Please try again.');
    }
  },

  /**
   * Verify the OTP provided by the user.
   * @param phoneNumber 10-digit phone number
   * @param otp 6-digit verification code
   * @param deviceId persistent unique device identifier
   * @param fcmToken FCM messaging token for push notifications
   */
  verifyOtp: async (
    phoneNumber: string,
    otp: string,
    deviceId?: string | null,
    fcmToken?: string | null
  ): Promise<{ status: number; data: VerifyOtpResponse }> => {
    try {
      const payload: any = {
        phoneNumber: Number(phoneNumber),
        otp: Number(otp),
      };

      if (deviceId) {
        payload.deviceId = deviceId;
      }
      if (fcmToken) {
        payload.fcmToken = fcmToken;
      }
      payload.platform = Platform.OS.toUpperCase();

      const response = await apiClient.post<VerifyOtpResponse>(
        API_ENDPOINTS.AUTH.VERIFY_OTP,
        payload
      );
      if (response.data.status === 'success' || response.status === 200) {
        // Store tokens securely
        await Promise.all([
          Keychain.setGenericPassword('auth_token', response.data.token, {
            service: 'auth_token',
          }),
          Keychain.setGenericPassword('refresh_token', response.data.refreshToken, {
            service: 'refresh_token',
          }),
        ]);
      }

      return {
        status: response.status,
        data: response.data,
      };
    } catch (error: any) {
      if (error.response) {
        throw new Error(error.response.data.message || 'OTP Verification failed');
      }
      throw new Error('Network error. Please try again.');
    }
  },

  truecallerLogin: async (
    authorizationCode: string,
    deviceId?: string | null,
    fcmToken?: string | null,
    codeVerifier?: string
  ): Promise<{ status: number; data: VerifyOtpResponse }> => {
    try {
      const payload: any = { 
        authorizationCode,
        platform: Platform.OS.toUpperCase(),
      };
      if (codeVerifier) payload.codeVerifier = codeVerifier;
      if (deviceId) payload.deviceId = deviceId;
      if (fcmToken) payload.fcmToken = fcmToken;

      const response = await apiClient.post<VerifyOtpResponse>(
        API_ENDPOINTS.AUTH.TRUECALLER_LOGIN,
        payload
      );

      if (response.data.status === 'success' || response.status === 200) {
        await Promise.all([
          Keychain.setGenericPassword('auth_token', response.data.token, {
            service: 'auth_token',
          }),
          Keychain.setGenericPassword('refresh_token', response.data.refreshToken, {
            service: 'refresh_token',
          }),
        ]);
      }

      return { status: response.status, data: response.data };
    } catch (error: any) {
      if (error.response) {
        throw new Error(error.response.data.message || 'Truecaller verification failed');
      }
      throw new Error('Network error. Please try again.');
    }
  },

  logout: async (): Promise<void> => {
    try {
      const refreshCreds = await Keychain.getGenericPassword({ service: 'refresh_token' });

      if (refreshCreds) {
        const deviceId = await getDeviceId().catch(() => null);
        const payload: any = {
          refreshToken: refreshCreds.password
        };
        if (deviceId) {
          payload.deviceId = deviceId;
        }

        // Call logout API with refreshToken in body
        await apiClient.post(API_ENDPOINTS.AUTH.LOGOUT, payload);
      }
    } catch (error) {
      console.error('Logout API error', error);
    } finally {
      // Always clear local session
      await authService.clearLocalSession();
    }
  },

  clearLocalSession: async (): Promise<void> => {
    try {
      await Promise.all([
        Keychain.resetGenericPassword({ service: 'auth_token' }),
        Keychain.resetGenericPassword({ service: 'refresh_token' }),
      ]);
    } catch (e) {
      console.error('Failed to reset keychain', e);
    }
    // Reset Zustand store
    const { resetAllStores } = require('@/store/resetAllStores');
    resetAllStores();
  },

  resendOtp: async (
    phoneNumber: string,
  ): Promise<{ status: number; data: LoginResponse }> => {
    try {
      const response = await apiClient.post<LoginResponse>(
        API_ENDPOINTS.AUTH.RESEND_OTP,
        { phoneNumber }
      );
      return {
        status: response.status,
        data: response.data,
      };
    } catch (error: any) {
      if (error.response) {
        throw new Error(error.response.data.message || 'Resend OTP failed');
      }
      throw new Error('Network error. Please try again.');
    }
  },
};

import { API_ENDPOINTS } from '@/constants/apiEndpoints';
import apiClient from './apiClient';
import { Logger } from '@/utils/logger';

export interface ProfileUpdateData {
  fullName?: string;
  dob?: string;
  gender?: string;
  profileImage?: { uri: string } | null;
}

interface ReactNativeFile {
  uri: string;
  type: string;
  name: string;
}

export interface VehiclePayload {
  vehicleNumber: string;
  vehicleTypeId: number;
  company: string;
  model: string;
  color: string;
}

export const userService = {
  getProfile: async () => {
    const response = await apiClient.get(API_ENDPOINTS.USER.PROFILE);
    return response.data;
  },

  getUserProfile: async (userId: string) => {
    const response = await apiClient.get(`${API_ENDPOINTS.USER.PROFILE}?userId=${userId}`);
    return response.data;
  },

  getVehicles: async () => {
    const response = await apiClient.get(API_ENDPOINTS.USER.VEHICLES);
    return response.data;
  },

  saveVehicle: async (data: VehiclePayload) => {
    const response = await apiClient.post(API_ENDPOINTS.USER.VEHICLES, data);
    return response.data;
  },

  updateVehicle: async (id: string, data: VehiclePayload) => {
    const response = await apiClient.put(`${API_ENDPOINTS.USER.VEHICLES}/${id}`, data);
    return response.data;
  },

  deleteVehicle: async (id: string) => {
    const response = await apiClient.delete(`${API_ENDPOINTS.USER.VEHICLES}/${id}`);
    return response.data;
  },

  updateProfile: async (data: ProfileUpdateData) => {
    try {
      const formData = new FormData();

      if (data.fullName !== undefined) {
        formData.append('name', data.fullName);
      }

      if (data.dob !== undefined) {
        // Convert DD/MM/YYYY -> YYYY-MM-DD
        let formattedDate = data.dob;
        if (formattedDate && formattedDate.includes('/')) {
          const parts = formattedDate.split('/');
          if (parts.length === 3) {
            formattedDate = `${parts[2]}-${parts[1]}-${parts[0]}`;
          }
        }
        formData.append('date', formattedDate);
      }

      if (data.gender !== undefined) {
        formData.append('gender', data.gender ? data.gender.toUpperCase() : 'OTHER');
      }

      if (data.profileImage?.uri) {
        formData.append('file', {
          uri: data.profileImage.uri,
          type: 'image/jpeg',
          name: 'profile_image.jpg',
        } as unknown as Blob);
      }

      const response = await apiClient.post(API_ENDPOINTS.USER.PROFILE, formData);
      return response.data;
    } catch (error) {
      Logger.error('Error updating profile:', error);
      throw error;
    }
  },

  uploadProfilePhoto: async (imageUri: string) => {
    try {
      const formData = new FormData();
      formData.append('file', {
        uri: imageUri,
        type: 'image/jpeg',
        name: 'profile_image.jpg',
      } as unknown as Blob);

      const response = await apiClient.post(API_ENDPOINTS.USER.PROFILE, formData);
      return response.data;
    } catch (error) {
      Logger.error('Error uploading profile photo:', error);
      throw error;
    }
  },

  deleteProfilePhoto: async () => {
    try {
      const response = await apiClient.delete(API_ENDPOINTS.USER.DELETE_PHOTO);
      return response.data;
    } catch (error) {
      Logger.error('Error deleting profile photo:', error);
      throw error;
    }
  },
};

