}

// Global configuration setup targeting native system permission engines
Geolocation.setRNConfiguration({
  authorizationLevel: 'always',
  skipPermissionRequests: false,
  enableBackgroundLocationUpdates: true, // MANDATORY FOR IOS BACKGROUND STREAMING
  locationProvider: 'playServices', // MANDATORY FOR HIGH-PRECISION ANDROID ACCURACY
});

/**
 * Resolves a single snapshot of high-accuracy device location wrapped cleanly in a Promise.
 * This guarantees execution even when native stream listeners get frozen by the OS.
 */
const grabCurrentCoordinates = (highAccuracy: boolean): Promise<GeolocationResponse> => {
  return new Promise((resolve, reject) => {
    Geolocation.getCurrentPosition(
      position => resolve(position),
      error => reject(error),
      {
        enableHighAccuracy: highAccuracy,
        timeout: highAccuracy ? 15000 : 8000, // Short network timeout for passive mode
        maximumAge: highAccuracy ? 0 : 5000,   // Utilize cell tower/Wi-Fi positioning cache when stationary
      },
    );
  });
};

/**
 * Headless background task task execution loop.
 * Operates on a deterministic hardware-timed pulse pattern to maintain persistence.
 */
const locationTrackingTask = async (
  taskDataArguments?: TaskParams,
): Promise<void> => {
  const rideId = taskDataArguments?.rideId;
  if (!rideId) {
    Logger.error('[BackgroundLocation] Missing rideId in task parameters');
    return;
  }

  Logger.log(
    `[BackgroundLocation] Initializing loop thread for ride: ${rideId}`,
  );

  let lastValidLat = 0;
  let lastValidLng = 0;
  let regularIntervalDelay = 6000; // Default: update every 6 seconds
  let isHighAccuracyActive = true;
  let stationaryCycleCount = 0;

  while (BackgroundService.isRunning()) {
    const startTime = Date.now();

    try {
      // 1. Fetch current device location using dynamically toggled high accuracy or passive cellular providers
      const position = await grabCurrentCoordinates(isHighAccuracyActive);
      const { latitude, longitude, accuracy, speed } = position.coords;

      // ---- SCENARIO 1: ANTI-FRAUD & JUNK FILTERING ----
      // Ignore extreme outliers, dead zones, mock coordinates, or poor accuracy signatures (> 50 meters)
      if (latitude === 0 || longitude === 0 || accuracy > 50) {
        Logger.log(
          `[BackgroundLocation] Dropped low-quality hardware coordinate data. Accuracy: ${accuracy}m`,
        );
      } else {
        // ---- SCENARIO 2: JITTER & BATTERY THROTTLER ----
        // Calculate standard approximate delta shift (Haversine estimation shortcut)
        const latDelta = Math.abs(latitude - lastValidLat);
        const lngDelta = Math.abs(longitude - lastValidLng);

        // Check if device moved noticeably (approx ~8 meters shift in High-Accuracy or ~22 meters in Passive mode to filter cellular jitter)
        const movementThreshold = isHighAccuracyActive ? 0.00007 : 0.0002;

        if (latDelta > movementThreshold || lngDelta > movementThreshold) {
          // --- MOVEMENT WAKE-UP TRANSITION ---
          if (!isHighAccuracyActive) {
            isHighAccuracyActive = true;
            stationaryCycleCount = 0;
            Logger.log(
              '[BackgroundLocation] Motion detected in passive network mode. Waking up high-accuracy GPS engine instantly!',
            );
          }

          lastValidLat = latitude;
          lastValidLng = longitude;
          stationaryCycleCount = 0;

          // ---- SCENARIO 3: DYNAMIC REFRESH SPEEDS ----
          // If traveling fast (> 25km/h or ~7m/s), check more frequently to prevent map skipping
          regularIntervalDelay = speed && speed > 7 ? 4000 : 7000;

          try {
            // Dispatch validated payload downstream to server
            await rideService.updateLocation(rideId, latitude, longitude);
            Logger.log(
              `[BackgroundLocation] Dispatched location to service Manager: ${latitude}, ${longitude}`,
            );

            if (Platform.OS === 'android') {
              await BackgroundService.updateNotification({
                taskDesc: `Tracking active • Route updated live`,
              });
            }

            // Connection is active! Check if there is an offline backlog to upload
            if (locationQueue.size() > 0) {
              Logger.log(
                `[BackgroundLocation] Cellular radio restored. Syncing backlog of ${locationQueue.size()} entries.`,
              );
              const backlog = locationQueue.get();

              // Upload the complete sequence to the backend in a compressed payload
              await rideService.syncLocationBacklog(rideId, backlog);

              // Clean out the cache upon success
              locationQueue.flush();
              Logger.log('[BackgroundLocation] Offline backlog sync completed and purged.');
            }
          } catch (apiErr) {
            // Network dropped or signal dead zone encountered. Buffer the coordinate natively!
            Logger.warn(
              '[BackgroundLocation] Live dispatch failed (signal dead zone). Buffering coordinate locally.',
            );
            locationQueue.enqueue(latitude, longitude);

            if (Platform.OS === 'android') {
              await BackgroundService.updateNotification({
                taskDesc: `Tracking active (Offline) • ${locationQueue.size()} logs cached`,
              });
            }
          }
        } else {
          // Device is stationary. Increment stationary state duration checks.
          stationaryCycleCount++;

          if (isHighAccuracyActive && stationaryCycleCount >= 3) {
            // --- STATIONARY SLEEP TRANSITION ---
            // Vehicle has stopped moving completely for ~20-30 seconds (eating lunch, stuck at major signal).
            // Power off GPS chip completely and fall back to passive cell-tower/Wi-Fi tracking (saves 99% battery!)
            isHighAccuracyActive = false;
            Logger.log(
              '[BackgroundLocation] Vehicle stationary for 3 cycles. Powering off high-power GPS hardware and switching to passive low-power networking.',
            );

            if (Platform.OS === 'android') {
              await BackgroundService.updateNotification({
                taskDesc: `Tracking paused • Stationary battery-saving active`,
              });
            }
          }

          if (!isHighAccuracyActive) {
            // Slow down the passive check frequency to 15 seconds to maximize device sleep states
            regularIntervalDelay = 15000;
          } else {
            // Standard throttle before switching down GPS
            regularIntervalDelay = 12000;
          }

          Logger.log(
            `[BackgroundLocation] Device stationary. Throttling interval: ${regularIntervalDelay}ms (HighAccuracy GPS: ${isHighAccuracyActive})`,
          );
        }
      }
    } catch (hardwareError) {
      Logger.error(
        '[BackgroundLocation] Failed to acquire device telemetry:',
        hardwareError,
      );
      // In a signal dead zone (tunnel, underground parking), wait a bit before requesting hardware hooks again
      regularIntervalDelay = 10000;
    }

    // Determine processing execution latency offset to maintain a highly reliable, flat time tracking loop rhythm
    const runtimeDuration = Date.now() - startTime;
    const computedExecutionSleep = Math.max(
      1000,
      regularIntervalDelay - runtimeDuration,
    );

    await new Promise(resolve => setTimeout(resolve, computedExecutionSleep));
  }

  Logger.log('[BackgroundLocation] Core looping thread terminated safely.');
};

/**
 * Starts the persistent background location service.
 */
export const startBackgroundLocationTracking = async (
  rideId: string | number,
): Promise<void> => {
  if (BackgroundService.isRunning()) {
    Logger.log(
      '[BackgroundLocation] Core engine active. Stopping current process thread first.',
    );
    await stopBackgroundLocationTracking();
  }

  const options = {
    taskName: `Marg_Tracker_${rideId}`,
    taskTitle: 'Trip in Progress',
    taskDesc: 'Sharing live telemetry data with passengers...',
    taskIcon: {
      name: 'ic_launcher',
      type: 'mipmap',
    },
    color: '#00AA7B', // Marg Brand Green Accent
    linkingURI: `ridepoolcompany://ride-details/${rideId}`,
    foregroundServiceType: ['location'] as 'location'[], // Enforces explicit Android OS location classification
    parameters: {
      rideId,
    },
  };

  try {
    await BackgroundService.start(locationTrackingTask, options);
    Logger.log(
      `[BackgroundLocation] Engine initialized successfully for ride identifier: ${rideId}`,
    );
  } catch (error) {
    Logger.error(
      '[BackgroundLocation] Initialization routine critically faulted:',
      error,
    );
    throw error;
  }
};

/**
 * Stops the active persistent background location service.
 */
export const stopBackgroundLocationTracking = async (): Promise<void> => {
  try {
    if (BackgroundService.isRunning()) {
      await BackgroundService.stop();
      Logger.log(
        '[BackgroundLocation] Engine termination routines executed cleanly.',
      );
    }
  } catch (error) {
    Logger.error(
      '[BackgroundLocation] Engine termination routines faulted:',
      error,
    );
    throw error;
  }
};

import { format, parse, isValid } from 'date-fns';

/**
 * Formats a DOB string as the user types, automatically adding slashes.
 * @param text Current input text
 * @param prevText Previous input text (to detect deletion)
 */
export const formatDOBInput = (text: string, prevText: string): string => {
  // Only allow digits and slashes
  let cleaned = text.replace(/[^0-9/]/g, '');

  // Handle deletion - if user is deleting a slash, let them
  if (text.length < prevText.length && prevText.endsWith('/') && !text.endsWith('/')) {
    return cleaned;
  }

  // Auto-slash logic
  if (cleaned.length === 2 && !cleaned.includes('/')) {
    cleaned += '/';
  } else if (cleaned.length === 5 && cleaned.split('/').length === 2) {
    cleaned += '/';
  }

  // Limit to 10 characters (DD/MM/YYYY)
  return cleaned.slice(0, 10);
};

/**
 * Formats a Date object to DD/MM/YYYY string.
 */
export const formatDateToDDMMYYYY = (date: Date): string => {
  return format(date, 'dd/MM/yyyy');
};

/**
 * Parses a DD/MM/YYYY string into a Date object.
 * Returns current date if invalid.
 */
export const parseDateFromDDMMYYYY = (text: string): Date => {
  const parsed = parse(text, 'dd/MM/yyyy', new Date());
  return isValid(parsed) ? parsed : new Date();
};

/**
 * Safely parses any date string and returns a valid Date object.
 * If the date is invalid, it returns null instead of crashing.
 */
export const safeParseDate = (dateStr: any): Date | null => {
  if (!dateStr) return null;
  if (dateStr instanceof Date) {
    return isValid(dateStr) ? dateStr : null;
  }

  // Handle cross-platform iOS spaces and enforce UTC parsing for timezone-less ISO strings
  if (typeof dateStr === 'string') {
    let normalized = dateStr.trim().replace(' ', 'T');
    if (normalized.includes('T')) {
      const parts = normalized.split('T');
      const timePart = parts[1];
      // Check if timePart does not contain timezone indicator Z or offset (+/-)
      if (timePart && !timePart.includes('Z') && !timePart.includes('+') && !timePart.includes('-')) {
        normalized += 'Z';
      }
    }
    const d = new Date(normalized);
    if (isValid(d)) return d;
  }

  const d = new Date(dateStr);
  return isValid(d) ? d : null;
};

/**
 * Safely formats a date/time string to localized time.
 */
export const formatTimeSafely = (
  dateStr: any,
  options: Intl.DateTimeFormatOptions = { hour: '2-digit', minute: '2-digit' },
  fallback = 'TBD'
): string => {
  const parsed = safeParseDate(dateStr);
  if (!parsed) return fallback;
  try {
    return parsed.toLocaleTimeString([], options);
  } catch (e) {
    return fallback;
  }
};

/**
 * Safely formats a date/time string to localized date.
 */
export const formatDateSafely = (
  dateStr: any,
  options: Intl.DateTimeFormatOptions = { weekday: 'short', day: 'numeric', month: 'short' },
  fallback = 'TBD'
): string => {
  const parsed = safeParseDate(dateStr);
  if (!parsed) return fallback;
  try {
    return parsed.toLocaleDateString([], options);
  } catch (e) {
    return fallback;
  }
};

/**
 * Extract epoch milliseconds from any message date representation (timestamp or createdAt).
 */
export const parseChatTimestamp = (message: { timestamp?: number | string; createdAt?: string }): number => {
  if (message.timestamp) {
    const parsed = typeof message.timestamp === 'number' ? new Date(message.timestamp) : safeParseDate(message.timestamp);
    if (parsed) return parsed.getTime();
  }
  if (message.createdAt) {
    const parsed = safeParseDate(message.createdAt);
    if (parsed) return parsed.getTime();
  }
  return Date.now();
};

/**
 * Persistent Device ID Utility
 *
 * Generates a device ID that survives app uninstall/reinstall:
 * - iOS:     UUID stored in Keychain (Keychain persists across uninstalls)
 * - Android: Settings.Secure.ANDROID_ID (naturally persists across uninstalls)
 *
 * The resolved ID is cached in memory after first access for zero-cost reads.
 */
import { Platform } from 'react-native';
import * as Keychain from 'react-native-keychain';
import DeviceInfo from 'react-native-device-info';
import { Logger } from '@/utils/logger';

/** Keychain service name dedicated to the device identifier */
const DEVICE_ID_SERVICE = 'ridepool_device_id';

/** In-memory cache so repeated calls never hit async storage twice */
let cachedDeviceId: string | null = null;

/**
 * Generate a RFC-4122 v4-style UUID without external dependencies.
 * Used exclusively on iOS for first-time Keychain seeding.
 */
const generateUUID = (): string => {
  const hex = '0123456789abcdef';
  let uuid = '';
  for (let i = 0; i < 36; i++) {
    if (i === 8 || i === 13 || i === 18 || i === 23) {
      uuid += '-';
    } else if (i === 14) {
      uuid += '4';
    } else if (i === 19) {
      uuid += hex[(Math.random() * 4) | 8];
    } else {
      uuid += hex[(Math.random() * 16) | 0];
    }
  }
  return uuid;
};

/**
 * Retrieve (or create) a persistent device identifier.
 *
 * @returns A promise that resolves to a stable, unique device ID string.
 */
export const getDeviceId = async (): Promise<string> => {
  // Return from memory cache if available
  if (cachedDeviceId) {
    return cachedDeviceId;
  }

  try {
    if (Platform.OS === 'ios') {
      return await getIOSDeviceId();
    }
    return await getAndroidDeviceId();
  } catch (error) {
    Logger.error('[DeviceId] Failed to resolve device ID:', error);
    // Ultimate fallback: generate a transient ID so the app never crashes
    const fallback = generateUUID();
    cachedDeviceId = fallback;
    return fallback;
  }
};

/**
 * iOS: Read from Keychain (persists across uninstall). Seed on first launch.
 */
const getIOSDeviceId = async (): Promise<string> => {
  const existing = await Keychain.getGenericPassword({
    service: DEVICE_ID_SERVICE,
  });

  if (existing && existing.password) {
    cachedDeviceId = existing.password;
    Logger.log('[DeviceId] iOS – restored from Keychain');
    return existing.password;
  }

  // First launch: generate and persist
  const newId = generateUUID();
  await Keychain.setGenericPassword(DEVICE_ID_SERVICE, newId, {
    service: DEVICE_ID_SERVICE,
    accessible: Keychain.ACCESSIBLE.AFTER_FIRST_UNLOCK_THIS_DEVICE_ONLY,
  });

  cachedDeviceId = newId;
  Logger.log('[DeviceId] iOS – created new ID and stored in Keychain');
  return newId;
};

/**
 * Android: Read ANDROID_ID via react-native-device-info.
 * This value is tied to the signing key and user, and naturally
 * persists across uninstalls (resets only on factory reset).
 */
const getAndroidDeviceId = async (): Promise<string> => {
  const androidId = await DeviceInfo.getAndroidId();

  if (androidId) {
    cachedDeviceId = androidId;
    Logger.log('[DeviceId] Android – resolved ANDROID_ID');
    return androidId;
  }

  // Fallback: use unique device ID from device-info
  const uniqueId = await DeviceInfo.getUniqueId();
  cachedDeviceId = uniqueId;
  Logger.log('[DeviceId] Android – resolved via getUniqueId fallback');
  return uniqueId;
};

/**
 * Clear the in-memory device ID cache.
 * Useful during testing or when debugging identity issues.
 */
export const clearDeviceIdCache = (): void => {
  cachedDeviceId = null;
};

import { AxiosError } from 'axios';
import { useSettingsStore } from '@/store/settings';
import { en } from '@/constants/localization/en';
import { hi } from '@/constants/localization/hi';

const translations = { en, hi };

interface BackendErrorResponse {
  message?: string;
  success?: boolean;
  status?: number;
  details?: unknown;
}

/**
 * Safely extracts a backend-returned or standard error message.
 * Inspects the detailed response data first, then falls back to standard Axios error strings, 
 * and finally defaults to the provided fallback message.
 */
export const getErrorMessage = (error: unknown, fallbackMessage?: string): string => {
  if (error && typeof error === 'object') {
    const axiosError = error as AxiosError<BackendErrorResponse>;
    let responseData: any = axiosError.response?.data;

    if (typeof responseData === 'string') {
      try {
        responseData = JSON.parse(responseData);
      } catch (e) {
        // Not a JSON string
      }
    }

    if (responseData?.message) {
      const message = responseData.message;
      if (message === 'You already have an active booking during this time. Please complete or cancel it first.') {
        const lang = useSettingsStore.getState().language || 'en';
        return translations[lang].notification.activeBookingOverlap;
      }
      return message;
    }

    if (axiosError.message) {
      // In Axios, 400 errors have a default message 'Request failed with status code 400'
      // We only fallback to it if no backend message is provided
      return axiosError.message;
    }
  }
  return fallbackMessage || 'An unexpected error occurred';
};

/**
 * Custom Logger utility that toggles behavior between Development and Production.
 */
const Logger = {
  log: (...args: unknown[]) => {
    if (__DEV__) {
      console.log('[LOG]:', ...args);
    }
  },
  error: (...args: unknown[]) => {
    if (__DEV__) {
      console.error('[ERROR]:', ...args);
    } else {
      // In production, you might want to send this to a service like Sentry or Firebase Crashlytics
      // For now, we'll just ignore or use a silent log
    }
  },
  warn: (...args: unknown[]) => {
    if (__DEV__) {
      console.warn('[WARN]:', ...args);
    }
  },
  info: (...args: unknown[]) => {
    if (__DEV__) {
      console.info('[INFO]:', ...args);
    }
  },
};

export { Logger };

import { ENABLE_NETWORK_LOGGER } from '@env';

const REDACTED_VALUE = '[REDACTED]';
const FORM_DATA_VALUE = '[FORM_DATA]';

const SENSITIVE_KEY_PARTS = [
  'authorization',
  'token',
  'password',
  'otp',
  'phone',
  'secret',
  'credential',
  'key',
];

type JsonRecord = Record<string, unknown>;

const isRecord = (value: unknown): value is JsonRecord =>
  typeof value === 'object' && value !== null && !Array.isArray(value);

const hasToJSON = (value: unknown): value is { toJSON: () => unknown } =>
  isRecord(value) && typeof value.toJSON === 'function';

const isFormDataValue = (value: unknown): boolean =>
  typeof FormData !== 'undefined' && value instanceof FormData;

const isSensitiveKey = (key: string): boolean => {
  const normalizedKey = key.toLowerCase();
  return SENSITIVE_KEY_PARTS.some(part => normalizedKey.includes(part));
};

export const isNetworkLoggerEnabled = (): boolean =>
  true;

export const redactSensitiveData = (value: unknown): unknown => {
  if (value === null || value === undefined) {
    return value;
  }

  // if (isFormDataValue(value)) {
  //   return value;
  // }

  if (Array.isArray(value)) {
    return value.map(item => redactSensitiveData(item));
  }

  if (!isRecord(value)) {
    return value;
  }

  return Object.entries(value).reduce<JsonRecord>((acc, [key, item]) => {
    acc[key] = redactSensitiveData(item);
    return acc;
  }, {});
};

export const sanitizeHeaders = (headers: unknown): JsonRecord => {
  const headerSource = hasToJSON(headers) ? headers.toJSON() : headers;

  if (!isRecord(headerSource)) {
    return {};
  }

  return Object.entries(headerSource).reduce<JsonRecord>((acc, [key, value]) => {
    acc[key] = value;
    return acc;
  }, {});
};
